export const SCENE_SOURCES: Record<string, string> = {
  "types.ts": "import type { EasingSpec } from './easing';\n\n// ----- Control vocabulary. Templates may ONLY use these types. -----\nexport type ControlType =\n  | 'slider'   // numeric, inline editable value.  needs min,max,step\n  | 'toggle'   // two-state segmented (Forward/Reverse, On/Off)\n  | 'pills'    // single-select option row.         needs options[]\n  | 'select'   // dropdown.                         needs options[]\n  | 'color'    // hex string\n  | 'xypad'    // {x,y}\n  | 'upload'   // file/url\n  | 'text';    // string\n\nexport interface ControlDef {\n  key: string;                 // unique within the template\n  label: string;               // shown in panel\n  type: ControlType;\n  min?: number; max?: number; step?: number;  // slider\n  options?: string[];          // pills / select / toggle\n  default: number | string | boolean | { x: number; y: number };\n}\n\n// ----- What a template's transform returns for ONE layer at ONE frame -----\nexport interface LayerTransform {\n  x: number;         // px, canvas centre = 0,0\n  y: number;\n  scale: number;     // 1 = native\n  rotation: number;  // radians\n  alpha: number;     // 0..1\n  skewX?: number;    // optional, for fake-3D tilt\n  skewY?: number;\n  scaleX?: number;   // optional non-uniform squash (default 1) — flips/page turns\n  scaleY?: number;   // optional non-uniform squash (default 1) — split-flap\n  depth: number;     // sort order; higher = drawn on top / nearer\n}\n\n// ----- What a webgl template's transform3d returns for ONE layer -----\n// World units: 1 unit = 1 preview px on the z=0 plane; +z is toward the\n// camera; y follows canvas convention (down = positive), the renderer flips.\nexport interface LayerTransform3D {\n  x: number;\n  y: number;\n  z: number;\n  rotationX?: number;  // radians\n  rotationY?: number;\n  rotationZ?: number;\n  scale: number;\n  alpha: number;\n}\n\n// ----- The transform context handed to every template each frame -----\nexport interface TransformCtx {\n  fps: number;\n  width: number;\n  height: number;\n  duration: number;     // clip length in seconds\n  totalFrames: number;  // max(1, round(duration * fps)) — the loop length\n  // The scene's active easing curve, t∈[0,1] → y (see lib/easing).\n  ease: (t: number) => number;\n  // Remap a cyclic phase so each unit step is shaped by `ease`, keeping the\n  // loop seamless: floor(p) + ease(frac(p)). Templates route their raw\n  // (time·speed) phase through this to inherit the scene easing.\n  easedPhase: (phase: number) => number;\n}\n\n// ----- A motion template (SEAM 1) -----\nexport interface Template {\n  meta: {\n    id: string; name: string; group: string; thumbnail?: string;\n    defaultEasing?: EasingSpec;               // curve the template ships with\n    repeatAssets?: boolean;                   // slot i shows asset i % assets.length (high-count fields)\n    engine?: 'pixi' | 'webgl';                // renderer backend; default 'pixi'\n    cardAspect?: number | 'canvas';           // cover-crop shape: w/h ratio (default 4/5) or the canvas aspect (full-bleed)\n  };\n  controls: ControlDef[];                     // its FULL own set\n  transform: (\n    frame: number,                            // absolute frame index\n    index: number,                            // this layer's slot 0..count-1\n    count: number,                            // total active layers\n    values: Record<string, any>,              // current control values\n    ctx: TransformCtx                          // canvas ctx + easing\n  ) => LayerTransform;                         // PURE. no side effects.\n  // webgl templates additionally provide real-3D poses; the 2D transform\n  // stays as the thumbnail/fallback projection.\n  transform3d?: (\n    frame: number,\n    index: number,\n    count: number,\n    values: Record<string, any>,\n    ctx: TransformCtx\n  ) => LayerTransform3D;                       // PURE. no side effects.\n}\n",
  "easing.ts": "// ============================================================\n//  EASING ENGINE\n//  A shared library of easing curves — cubic-bezier presets plus\n//  physics curves (bounce / spring / wiggle / overshoot) — used to\n//  reshape how every template advances through its motion cycle.\n//\n//  A curve is a pure map t∈[0,1] → y, with f(0)=0 and f(1)=1 so it\n//  can be dropped into a seamless loop without a discontinuity at the\n//  cycle boundary (see ctx.easedPhase in the renderer).\n// ============================================================\n\nexport type Bezier = [number, number, number, number]; // x1,y1,x2,y2\n\n// What the store persists: either a named preset, or a custom bezier.\nexport interface EasingSpec {\n  id: string;               // preset id, or 'custom'\n  bezier?: Bezier;          // present when id === 'custom'\n}\n\nexport interface EasingPreset {\n  id: string;\n  label: string;\n  group: 'signature' | 'standard' | 'physics';\n  bezier?: Bezier;          // bezier-backed presets (editable in the curve editor)\n  fn?: (t: number) => number; // physics curves (no bezier handles)\n}\n\n// ---------- cubic-bezier evaluator (CSS timing-function maths) ----------\n// Given the two control points (endpoints fixed at 0,0 and 1,1), returns a\n// function x→y solving for the parametric t via Newton-Raphson + bisection.\nexport function cubicBezier(x1: number, y1: number, x2: number, y2: number): (x: number) => number {\n  const cx = 3 * x1, bx = 3 * (x2 - x1) - cx, ax = 1 - cx - bx;\n  const cy = 3 * y1, by = 3 * (y2 - y1) - cy, ay = 1 - cy - by;\n\n  const sampleX = (t: number) => ((ax * t + bx) * t + cx) * t;\n  const sampleY = (t: number) => ((ay * t + by) * t + cy) * t;\n  const sampleDX = (t: number) => (3 * ax * t + 2 * bx) * t + cx;\n\n  const solveX = (x: number) => {\n    let t = x;\n    for (let i = 0; i < 8; i++) {\n      const dx = sampleX(t) - x;\n      if (Math.abs(dx) < 1e-6) return t;\n      const d = sampleDX(t);\n      if (Math.abs(d) < 1e-6) break;\n      t -= dx / d;\n    }\n    // bisection fallback\n    let lo = 0, hi = 1;\n    t = x;\n    while (lo < hi) {\n      const xm = sampleX(t);\n      if (Math.abs(xm - x) < 1e-6) return t;\n      if (x > xm) lo = t; else hi = t;\n      t = (lo + hi) / 2;\n    }\n    return t;\n  };\n\n  return (x: number) => (x <= 0 ? 0 : x >= 1 ? 1 : sampleY(solveX(x)));\n}\n\n// ---------- physics curves ----------\n// easeOutBounce — the classic three-bounce settle.\nfunction bounce(t: number): number {\n  const n1 = 7.5625, d1 = 2.75;\n  if (t < 1 / d1) return n1 * t * t;\n  if (t < 2 / d1) { t -= 1.5 / d1; return n1 * t * t + 0.75; }\n  if (t < 2.5 / d1) { t -= 2.25 / d1; return n1 * t * t + 0.9375; }\n  t -= 2.625 / d1; return n1 * t * t + 0.984375;\n}\n\n// Damped harmonic settle, normalized so f(0)=0 and f(1)=1 exactly.\nfunction springRaw(t: number): number {\n  return 1 - Math.exp(-6 * t) * Math.cos(3 * Math.PI * t);\n}\nconst SPRING_0 = springRaw(0), SPRING_1 = springRaw(1);\nfunction spring(t: number): number {\n  return (springRaw(t) - SPRING_0) / (SPRING_1 - SPRING_0);\n}\n\n// Wobble around the linear path, resolving exactly on 0 and 1.\nfunction wiggle(t: number): number {\n  return t + Math.sin(t * Math.PI * 6) * 0.12;\n}\n\n// easeOutBack — shoots past the target then eases back.\nfunction overshoot(t: number): number {\n  const c1 = 1.70158, c3 = c1 + 1;\n  const u = t - 1;\n  return 1 + c3 * u * u * u + c1 * u * u;\n}\n\n// ---------- preset registry ----------\n// Signature presets and their bezier values are lifted from the reference tool.\nexport const EASING_PRESETS: EasingPreset[] = [\n  // Signature (the named curves shown by default)\n  { id: 'flow',   label: 'Flow',   group: 'signature', bezier: [0.86, 0.14, 0.14, 0.86] },\n  { id: 'glide',  label: 'Glide',  group: 'signature', bezier: [0.33, 0.00, 0.00, 1.00] },\n  { id: 'linear', label: 'Linear', group: 'signature', bezier: [0.25, 0.25, 0.75, 0.75] },\n  { id: 'ease',   label: 'Ease',   group: 'signature', bezier: [0.87, 0.00, 0.13, 1.00] },\n  { id: 'sweep',  label: 'Sweep',  group: 'signature', bezier: [0.70, 0.10, 0.30, 0.90] },\n  { id: 'smooth', label: 'Smooth', group: 'signature', bezier: [0.76, 0.00, 0.24, 1.00] },\n  { id: 'flip',   label: 'Flip',   group: 'signature', bezier: [0.33, 0.00, 0.57, 1.00] },\n  { id: 'settle', label: 'Settle', group: 'signature', bezier: [0.80, 0.27, 0.20, 0.75] },\n  { id: 'snap',   label: 'Snap',   group: 'signature', bezier: [1.00, 0.00, 0.00, 1.00] },\n\n  // Standard in / out / in-out families\n  { id: 'sineIn',    label: 'Sine In',     group: 'standard', bezier: [0.12, 0.00, 0.39, 0.00] },\n  { id: 'sineOut',   label: 'Sine Out',    group: 'standard', bezier: [0.61, 1.00, 0.88, 1.00] },\n  { id: 'sineInOut', label: 'Sine In-Out', group: 'standard', bezier: [0.37, 0.00, 0.63, 1.00] },\n  { id: 'quadIn',    label: 'Quad In',     group: 'standard', bezier: [0.11, 0.00, 0.50, 0.00] },\n  { id: 'quadOut',   label: 'Quad Out',    group: 'standard', bezier: [0.50, 1.00, 0.89, 1.00] },\n  { id: 'quadInOut', label: 'Quad In-Out', group: 'standard', bezier: [0.45, 0.00, 0.55, 1.00] },\n  { id: 'cubicIn',    label: 'Cubic In',     group: 'standard', bezier: [0.32, 0.00, 0.67, 0.00] },\n  { id: 'cubicOut',   label: 'Cubic Out',    group: 'standard', bezier: [0.33, 1.00, 0.68, 1.00] },\n  { id: 'cubicInOut', label: 'Cubic In-Out', group: 'standard', bezier: [0.65, 0.00, 0.35, 1.00] },\n  { id: 'quartIn',    label: 'Quart In',     group: 'standard', bezier: [0.50, 0.00, 0.75, 0.00] },\n  { id: 'quartOut',   label: 'Quart Out',    group: 'standard', bezier: [0.25, 1.00, 0.50, 1.00] },\n  { id: 'quartInOut', label: 'Quart In-Out', group: 'standard', bezier: [0.76, 0.00, 0.24, 1.00] },\n  { id: 'expoIn',    label: 'Expo In',     group: 'standard', bezier: [0.70, 0.00, 0.84, 0.00] },\n  { id: 'expoOut',   label: 'Expo Out',    group: 'standard', bezier: [0.16, 1.00, 0.30, 1.00] },\n  { id: 'expoInOut', label: 'Expo In-Out', group: 'standard', bezier: [0.87, 0.00, 0.13, 1.00] },\n\n  // Physics (no bezier handles — sampled directly)\n  { id: 'bounce',    label: 'Bounce',    group: 'physics', fn: bounce },\n  { id: 'spring',    label: 'Spring',    group: 'physics', fn: spring },\n  { id: 'wiggle',    label: 'Wiggle',    group: 'physics', fn: wiggle },\n  { id: 'overshoot', label: 'Overshoot', group: 'physics', fn: overshoot },\n];\n\nexport const EASING_MAP: Record<string, EasingPreset> = Object.fromEntries(\n  EASING_PRESETS.map((p) => [p.id, p])\n);\n\nexport const DEFAULT_EASING: EasingSpec = { id: 'linear' };\n\n// Resolve a stored spec into an evaluatable curve.\nexport function resolveEasing(spec: EasingSpec | undefined): (t: number) => number {\n  if (!spec) return (t) => t;\n  if (spec.id === 'custom' && spec.bezier) {\n    const [a, b, c, d] = spec.bezier;\n    return cubicBezier(a, b, c, d);\n  }\n  const preset = EASING_MAP[spec.id];\n  if (!preset) return (t) => t;\n  if (preset.fn) return preset.fn;\n  if (preset.bezier) {\n    const [a, b, c, d] = preset.bezier;\n    return cubicBezier(a, b, c, d);\n  }\n  return (t) => t;\n}\n\n// The bezier control points a spec exposes to the editor, or null for a\n// physics curve (which has no draggable handles).\nexport function easingBezier(spec: EasingSpec | undefined): Bezier | null {\n  if (!spec) return null;\n  if (spec.id === 'custom') return spec.bezier ?? null;\n  const preset = EASING_MAP[spec.id];\n  return preset?.bezier ?? null;\n}\n\n// Sample a curve into [x,y] points for drawing (x linear across [0,1]).\nexport function sampleEasing(fn: (t: number) => number, n = 48): [number, number][] {\n  const pts: [number, number][] = [];\n  for (let i = 0; i <= n; i++) {\n    const x = i / n;\n    pts.push([x, fn(x)]);\n  }\n  return pts;\n}\n",
  "motion.ts": "// ============================================================\n//  MOTION HELPERS\n//  Small pure primitives shared by templates — the same shapes the\n//  reference app uses in its planner/scene expressions. Keeping them\n//  here means every template staggers, pulses, and settles the same way.\n// ============================================================\n\nexport const TAU = Math.PI * 2;\n\nexport const clamp = (x: number, a: number, b: number) => Math.max(a, Math.min(b, x));\n\n// Fractional part, always in [0,1) even for negative inputs.\nexport const frac = (x: number) => x - Math.floor(x);\n\n// Smooth 0 → 1 → 0 pulse over one unit (peaks at 0.5). Matches the reference\n// `wave` used across its motion expressions.\nexport const wave = (x: number) => Math.sin(Math.PI * frac(x));\n\n// Smoothstep 0..1 (ease-in-out with zero slope at both ends).\nexport const smooth = (x: number) => {\n  x = clamp(x, 0, 1);\n  return x * x * (3 - 2 * x);\n};\n\nexport const lerp = (a: number, b: number, t: number) => a + (b - a) * t;\n\n// Per-card staggered cycle time: each layer offsets its own normalized time by\n// its normalized index (u = i/(n-1)) × amount, so cards move individually\n// rather than as a block — the canonical `mod(t + u*stagger, 1)` form.\nexport function staggered(t: number, index: number, count: number, amount: number): number {\n  const u = count > 1 ? index / (count - 1) : 0;\n  return frac(t + u * amount);\n}\n\n// Quantize a units/sec speed so a full clip covers a whole number of motif\n// periods — the guarantee that frame totalFrames ≡ frame 0 (seamless loops in\n// preview and export). `period` is the phase distance after which the template\n// repeats: 1 for most conveyors, `count` for lifecycle templates whose state\n// wraps every count units (scale, stack). Returns total phase units per clip;\n// use as: phase = easedPhase((frame / ctx.totalFrames) * loopCycles(...)).\nexport function loopCycles(speed: number, duration: number, period = 1): number {\n  if (speed === 0) return 0;\n  const laps = Math.max(1, Math.round((Math.abs(speed) * duration) / period));\n  return Math.sign(speed) * laps * period;\n}\n\n// Remap a phase so each unit step holds still for `hold`∈[0,1) of the step,\n// then eases across the remainder with `shape`. f(n)=n at integers, so it is\n// loop-safe. Used for stepped marquee/ticker motion.\nexport function stepHold(p: number, hold: number, shape: (t: number) => number = smooth): number {\n  const u = frac(p);\n  const h = clamp(hold, 0, 0.95);\n  return Math.floor(p) + (u <= h ? 0 : shape((u - h) / (1 - h)));\n}\n\n// Deterministic 2D hash → [0,1). Seeded-random scatter that is stable across\n// frames and reproducible for a given (index, seed) pair.\nexport const hash2 = (a: number, b: number) =>\n  frac(Math.sin(a * 127.1 + b * 311.7 + 1.7) * 43758.5453);\n\n// Which asset a layer slot shows. Templates with meta.repeatAssets cycle a\n// small image set across many layers; everything else binds 1:1.\nexport const assetIndexForSlot = (slot: number, assetCount: number, repeat: boolean) =>\n  repeat && assetCount > 0 ? slot % assetCount : slot;\n",
  "cardPath.ts": "export type PathKind = 'line' | 'arc' | 'ring' | 'zwall';\n\nexport interface CardPathParams {\n  kind: PathKind;\n  index: number;\n  count: number;\n  phase: number;      // advancing position along the path, in \"card units\"\n  radius?: number;    // arc/ring/zwall\n  gap?: number;       // line/arc spacing\n  arcSpan?: number;   // radians, for arc\n  wrap?: boolean;     // line: recycle cards into a symmetric window → seamless loop\n}\n\nexport interface CardPathResult {\n  x: number;\n  y: number;\n  featuredness: number;  // 1 = at phase centre, → 0 with distance\n  depthNorm: number;     // 0..1 along path, for depth sorting & fake-3D scale\n}\n\n// slot position relative to the moving phase, in card units\n// e.g. index 3 with phase 2.4 → offset 0.6\nexport function cardPath(p: CardPathParams): CardPathResult {\n  let offset = p.index - p.phase;                   // signed distance from centre\n  // Optional wrap: fold offset into [-count/2, count/2) so cards recycle endlessly\n  // and always fill both sides of the view (seamless carousel loop). Applies to\n  // line AND arc paths (ring wraps intrinsically via its angle).\n  if (p.wrap && p.count > 0) {\n    offset = ((offset % p.count) + p.count) % p.count;\n    if (offset > p.count / 2) offset -= p.count;\n  }\n  const dist = Math.abs(offset);\n  const featuredness = Math.max(0, 1 - dist);       // linear falloff; templates may curve it\n\n  let x = 0, y = 0, depthNorm = 0.5;\n\n  switch (p.kind) {\n    case 'line': {                                   // Carousel / Stories strip\n      x = offset * (p.gap ?? 200);\n      y = 0;\n      depthNorm = 1 - Math.min(1, dist / (p.count / 2));\n      break;\n    }\n    case 'arc': {                                    // Wheel arc / fan\n      const span = p.arcSpan ?? Math.PI;             // total sweep\n      const a = -span / 2 + (offset + p.count / 2) * (span / p.count);\n      x = Math.sin(a) * (p.radius ?? 400);\n      y = -Math.cos(a) * (p.radius ?? 400) + (p.radius ?? 400);\n      depthNorm = 1 - Math.min(1, dist / (p.count / 2));\n      break;\n    }\n    case 'ring': {                                   // Wheel full ring\n      const a = (p.index / p.count) * Math.PI * 2 - p.phase * (Math.PI * 2 / p.count);\n      x = Math.sin(a) * (p.radius ?? 400);\n      y = -Math.cos(a) * (p.radius ?? 400);\n      depthNorm = (Math.cos(a) + 1) / 2;             // front of ring = nearer\n      break;\n    }\n    case 'zwall': {                                  // 3D depth wall\n      // cards recede along Z; nearer = bigger, later slots further back\n      const z = offset;                              // in card units\n      depthNorm = 1 - Math.min(1, Math.max(0, (z + p.count / 2) / p.count));\n      x = 0; y = 0;                                  // template applies perspective scale via depthNorm\n      break;\n    }\n  }\n  return { x, y, featuredness, depthNorm };\n}\n",
  "boardPose.ts": "// ============================================================\n//  BOARD MODE — THE STATIC ARRANGEMENT (layer 1 of the compose stack)\n//  A frame-independent arrangement of the board's cards, authored with the\n//  same slider vocabulary the animation templates use (tilt / rotate /\n//  perspective / gap / scale). It is the *resting* pose: with motion off it is\n//  the whole picture, and with an animation on it is the base the motion is\n//  added on top of (see composedPose in lib/boardCompose).\n//\n//  Every value is addressable per slot via `perCard`, even though this first\n//  stage only sets the group values. That is deliberate: the next stage layers\n//  per-card hover interactions on top, and they must be able to move ONE card\n//  without the group arrangement being rewritten — the mistake that flattens\n//  detail when a block-wide instruction owns every card.\n//\n//  This lives apart from the Web spike on purpose: it is its own mode.\n// ============================================================\n\nimport type { LayerTransform, ControlDef } from './types';\n\n// A board pose is a LayerTransform plus DOM-only true-3D fields. The Pixi/web\n// pipelines never see it; only the board's own CSS mapping reads the extras.\nexport interface BoardTransform extends LayerTransform {\n  rotateX?: number;      // radians, tilt about the horizontal axis\n  rotateY?: number;      // radians, tilt about the vertical axis\n  perspective?: number;  // px; the CSS perspective the 3D tilt is seen through\n  // The animation's motion, to be applied INSIDE the tilted plane (after the 3D\n  // rotates) rather than in flat screen space — so a template's slide follows\n  // the plane the board tilted the cards onto. Set by composedPose.\n  motionX?: number;\n  motionY?: number;\n}\n\nexport type Arrangement = 'row' | 'fan' | 'stack' | 'grid';\n\nexport interface BoardValues {\n  arrangement: Arrangement;\n  front: 'first' | 'last'; // which card sits on top of the stack (z-order)\n  gapX: number;         // px horizontal spacing / step between cards\n  gapY: number;         // px vertical step per card — a positive value staircases them\n  cols: number;         // grid columns\n  rotate: number;       // deg — per-card spread (fan) or uniform tilt (row/stack/grid)\n  tiltX: number;        // deg — uniform 3D tilt about the horizontal axis\n  tiltY: number;        // deg — uniform 3D tilt about the vertical axis\n  perspective: number;  // px — CSS perspective the 3D tilt is seen through (0 = flat)\n  scale: number;        // uniform card scale\n  offset: { x: number; y: number };  // whole-board nudge\n}\n\n// Per-slot override: any subset of the group values, applied on top for card i.\nexport type BoardPerCard = Record<number, Partial<BoardValues>>;\n\nexport const BOARD_DEFAULTS: BoardValues = {\n  arrangement: 'row',\n  front: 'last',\n  gapX: 40,\n  gapY: 0,\n  cols: 3,\n  rotate: 0,\n  tiltX: 0,\n  tiltY: 0,\n  perspective: 0,\n  scale: 1,\n  offset: { x: 0, y: 0 },\n};\n\n// The board's controls, rendered by the same ControlRow the templates use.\nexport const BOARD_CONTROLS: ControlDef[] = [\n  { key: 'arrangement', label: 'Arrangement', type: 'pills', options: ['row', 'fan', 'stack', 'grid'], default: 'row' },\n  { key: 'front',       label: 'Front',       type: 'toggle', options: ['first', 'last'], default: 'last' },\n  { key: 'gapX',        label: 'Gap X',       type: 'slider', min: -300, max: 400, step: 1, default: 40 },\n  { key: 'gapY',        label: 'Gap Y',       type: 'slider', min: -300, max: 400, step: 1, default: 0 },\n  { key: 'cols',        label: 'Columns',     type: 'slider', min: 1, max: 6, step: 1,     default: 3 },\n  { key: 'rotate',      label: 'Rotate',      type: 'slider', min: -180, max: 180, step: 1, default: 0 },\n  { key: 'tiltX',       label: 'Tilt X',      type: 'slider', min: -80, max: 80, step: 1,  default: 0 },\n  { key: 'tiltY',       label: 'Tilt Y',      type: 'slider', min: -80, max: 80, step: 1,  default: 0 },\n  { key: 'perspective', label: 'Perspective', type: 'slider', min: 0, max: 2000, step: 10, default: 0 },\n  { key: 'scale',       label: 'Scale',       type: 'slider', min: 0.1, max: 3, step: 0.05, default: 1 },\n  { key: 'offset',      label: 'Offset',      type: 'xypad',                                default: { x: 0, y: 0 } },\n];\n\nconst DEG = Math.PI / 180;\n\n// A nominal per-card footprint, so `gap` reads as a space between cards rather\n// than a raw coordinate step. The board doesn't know the real card size (that\n// lives in the DOM), so the arrangements share this nominal width.\nconst CARD = 240;\n\n// Merge the group values with a slot's override (the next stage populates perCard).\nfunction valuesForSlot(board: BoardValues, perCard: BoardPerCard | undefined, i: number): BoardValues {\n  const o = perCard?.[i];\n  return o ? { ...board, ...o, offset: { ...board.offset, ...(o.offset ?? {}) } } : board;\n}\n\n// Pure, frame-independent. Returns where card `i` rests and how it is tilted.\nexport function boardPose(\n  i: number,\n  count: number,\n  board: BoardValues,\n  perCard?: BoardPerCard,\n): BoardTransform {\n  const v = valuesForSlot(board, perCard, i);\n  const n = Math.max(1, count);\n  const mid = (n - 1) / 2;\n\n  // z-order: 'last' keeps the natural order (card i on top of card i-1); 'first'\n  // flips it so card 0 sits on top. Only the stacking order changes — every\n  // card's position/tilt is untouched.\n  let x = 0, y = 0, rotation = 0, depth = v.front === 'first' ? (n - 1 - i) : i;\n\n  switch (v.arrangement) {\n    case 'row': {\n      // horizontal spacing from gapX; gapY steps each card down → a staircase.\n      x = (i - mid) * (CARD * v.scale + v.gapX);\n      y = (i - mid) * v.gapY;\n      rotation = v.rotate * DEG;\n      break;\n    }\n    case 'fan': {\n      // cards pivot around a low centre, spread by `rotate` degrees each.\n      const a = (i - mid) * v.rotate * DEG;\n      const radius = CARD * 1.6 * v.scale + v.gapX;\n      x = Math.sin(a) * radius;\n      y = (1 - Math.cos(a)) * radius + (i - mid) * v.gapY;\n      rotation = a;\n      break;\n    }\n    case 'stack': {\n      // an offset pile: each card nudged by gapX/gapY and rotated off the last.\n      x = (i - mid) * v.gapX;\n      y = (i - mid) * v.gapY;\n      rotation = (i - mid) * v.rotate * DEG;\n      break;\n    }\n    case 'grid': {\n      const cols = Math.max(1, Math.round(v.cols));\n      const rows = Math.ceil(n / cols);\n      const col = i % cols;\n      const row = Math.floor(i / cols);\n      const stepX = CARD * v.scale + v.gapX;\n      const stepY = CARD * v.scale + v.gapY;\n      x = (col - (cols - 1) / 2) * stepX;\n      y = (row - (rows - 1) / 2) * stepY;\n      rotation = v.rotate * DEG;\n      break;\n    }\n  }\n\n  return {\n    x: x + v.offset.x,\n    y: y + v.offset.y,\n    scale: v.scale,\n    rotation,\n    alpha: 1,\n    depth,\n    rotateX: v.tiltX * DEG,\n    rotateY: v.tiltY * DEG,\n    perspective: v.perspective,\n  };\n}\n",
  "boardCompose.ts": "// ============================================================\n//  BOARD MODE — COMPOSE STACK + CSS MAPPING\n//  final = board(i) ⊕ groupMotion(frame)\n//\n//  Layer 1 is the static board (lib/boardPose): where a card rests and how it\n//  is tilted. Layer 2 is the animation's *motion only* — its pose at `frame`\n//  minus its pose at frame 0, the same delta the Web spike's 'decorate' takes.\n//  Adding the delta (never replacing the board) is what keeps the group\n//  animation from erasing the arrangement, and leaves room for a per-card\n//  interaction layer to be added on top without either lower layer rewritten.\n//\n//  With `motionOn` false there is no template term: the board is the whole\n//  pose — the static version.\n// ============================================================\n\nimport type { Template, TransformCtx } from './types';\nimport { boardPose, type BoardTransform, type BoardValues, type BoardPerCard } from './boardPose';\n\nconst DEG = 180 / Math.PI;\n\n// One motion layer to stack on top of the board rest: a template sampled at a\n// per-card timing, weighted, its translation optionally mirrored. Every scene is\n// one of these — the final pose is board ⊕ Σ(layers).\nexport interface MotionLayer {\n  template: Template;\n  values: Record<string, any>;\n  frame: number;\n  motionIndex: number;\n  motionCount: number;\n  weight: number;      // 0..1 gate\n  motionSign: number;  // ±1, mirrors the layer's translation\n}\n\n// Compose the board rest with any number of motion layers. Each layer adds its\n// motion-only delta (its pose at `frame` minus its rest at 0), so layers stack\n// without erasing the board or each other: translations sum, scales multiply,\n// rotations/skews sum. `hideFade` pins alpha (card-scope hover keeps cards\n// solid). This is the general form of composedPose.\nexport function composedPoseLayers(\n  board: BoardValues,\n  perCard: BoardPerCard | undefined,\n  index: number,\n  count: number,\n  ctx: TransformCtx,\n  motionOn: boolean,\n  layers: MotionLayer[],\n  hideFade: boolean,\n): BoardTransform {\n  const base = boardPose(index, count, board, perCard);\n  if (!motionOn || layers.length === 0) return base;\n\n  let motionX = 0, motionY = 0;\n  let scale = base.scale, scaleX = base.scaleX ?? 1, scaleY = base.scaleY ?? 1;\n  let rotation = base.rotation, skewX = base.skewX ?? 0, skewY = base.skewY ?? 0;\n  let alpha = base.alpha;\n\n  for (const L of layers) {\n    const w = L.weight >= 1 ? 1 : L.weight <= 0 ? 0 : L.weight;\n    if (w <= 0) continue;\n    const rest = L.template.transform(0, L.motionIndex, L.motionCount, L.values, ctx);\n    const cur = L.template.transform(L.frame, L.motionIndex, L.motionCount, L.values, ctx);\n    motionX += (cur.x - rest.x) * w * L.motionSign;\n    motionY += (cur.y - rest.y) * w * L.motionSign;\n    // scale/skew are multiplicative/additive about each template's own rest pose\n    // (may not be identity), so normalize against it before composing.\n    scale *= 1 + ((rest.scale !== 0 ? cur.scale / rest.scale : 1) - 1) * w;\n    scaleX *= 1 + ((cur.scaleX ?? 1) / (rest.scaleX ?? 1) - 1) * w;\n    scaleY *= 1 + ((cur.scaleY ?? 1) / (rest.scaleY ?? 1) - 1) * w;\n    rotation += (cur.rotation - rest.rotation) * w;\n    skewX += ((cur.skewX ?? 0) - (rest.skewX ?? 0)) * w;\n    skewY += ((cur.skewY ?? 0) - (rest.skewY ?? 0)) * w;\n    if (!hideFade) alpha *= 1 + (cur.alpha - 1) * w; // else keep cards solid\n  }\n\n  return {\n    x: base.x, y: base.y,\n    motionX, motionY,\n    scale, scaleX, scaleY,\n    rotation, skewX, skewY,\n    alpha,\n    depth: base.depth,\n    rotateX: base.rotateX,\n    rotateY: base.rotateY,\n    perspective: base.perspective,\n  };\n}\n\nexport function composedPose(\n  template: Template,\n  board: BoardValues,\n  perCard: BoardPerCard | undefined,\n  motionOn: boolean,\n  frame: number,\n  index: number,\n  count: number,\n  values: Record<string, any>,\n  ctx: TransformCtx,\n  // Per-card motion weight 0..1 (the mouse-on-point hover layer). 1 = full\n  // animation, 0 = the static board rest with no motion. Neighbours of the\n  // hovered card get a fractional weight so the effect spills to nearby cards.\n  weight = 1,\n  // The (index, count) the TEMPLATE sees, decoupled from the board slot. Board\n  // position always comes from the real `index`; but the hover layer feeds a\n  // remapped pair so the card under the pointer becomes the front of a small\n  // local stack (motionIndex 0) that plays on its own clock — the animation\n  // triggers where the mouse is, not where the shared timeline happens to be.\n  motionIndex = index,\n  motionCount = count,\n  // Card-scope hover kills the template's fades: cards move but never fade in or\n  // out, so the deck opens/holds solid instead of dissolving mid-board.\n  hideFade = false,\n  // Flips the animation's translation so a reveal pushes cards AWAY from the\n  // pointer (open the deck) instead of toward it. −1 = away, +1 = as authored.\n  motionSign = 1,\n): BoardTransform {\n  const base = boardPose(index, count, board, perCard);\n  if (!motionOn || weight <= 0) return base;\n\n  const rest = template.transform(0, motionIndex, motionCount, values, ctx);\n  const cur = template.transform(frame, motionIndex, motionCount, values, ctx);\n\n  // Full-motion terms about the board rest, then scaled by `weight` so the card\n  // eases from its static pose (w=0) to the full animation (w=1). lerp(a,b,w).\n  const w = weight >= 1 ? 1 : weight;\n  const lerp = (a: number, b: number) => a + (b - a) * w;\n  return {\n    // The board arrangement fixes the on-screen position; the animation's\n    // translation is handed off as motionX/motionY so it can be applied inside\n    // the tilted plane (see boardTransformCss), not flat across the screen.\n    x: base.x,\n    y: base.y,\n    motionX: (cur.x - rest.x) * w * motionSign,\n    motionY: (cur.y - rest.y) * w * motionSign,\n    // scale/skew are multiplicative/additive about the template's own rest pose\n    // (which may not be identity), so normalize the motion against it before\n    // composing onto the board's scale.\n    scale: lerp(base.scale, base.scale * (rest.scale !== 0 ? cur.scale / rest.scale : 1)),\n    scaleX: lerp(base.scaleX ?? 1, (base.scaleX ?? 1) * ((cur.scaleX ?? 1) / (rest.scaleX ?? 1))),\n    scaleY: lerp(base.scaleY ?? 1, (base.scaleY ?? 1) * ((cur.scaleY ?? 1) / (rest.scaleY ?? 1))),\n    rotation: lerp(base.rotation, base.rotation + (cur.rotation - rest.rotation)),\n    skewX: lerp(base.skewX ?? 0, (base.skewX ?? 0) + ((cur.skewX ?? 0) - (rest.skewX ?? 0))),\n    skewY: lerp(base.skewY ?? 0, (base.skewY ?? 0) + ((cur.skewY ?? 0) - (rest.skewY ?? 0))),\n    // Alpha is absolute: a template that fades a layer means it to be faded —\n    // unless the hover layer asked to keep every card solid (hideFade).\n    alpha: hideFade ? base.alpha : lerp(base.alpha, cur.alpha),\n    depth: base.depth,\n    rotateX: base.rotateX,\n    rotateY: base.rotateY,\n    perspective: base.perspective,\n  };\n}\n\n// The CSS `transform` for a board pose. Cards are pinned at the stage centre\n// (left/top 50%), so the anchor pull-back leads, then the true-3D tilt.\nexport function boardTransformCss(t: BoardTransform): string {\n  const parts: string[] = [];\n  // perspective() must lead for the 3D tilt below it to be seen in depth.\n  if (t.perspective) parts.push(`perspective(${t.perspective.toFixed(0)}px)`);\n  parts.push(`translate(-50%, -50%)`);\n  parts.push(`translate(${t.x.toFixed(2)}px, ${t.y.toFixed(2)}px)`);\n  if (t.rotateX) parts.push(`rotateX(${(t.rotateX * DEG).toFixed(3)}deg)`);\n  if (t.rotateY) parts.push(`rotateY(${(t.rotateY * DEG).toFixed(3)}deg)`);\n  // The animation's slide runs here — after the 3D tilt — so it moves along the\n  // plane the cards were tilted onto, not flat across the screen.\n  if (t.motionX || t.motionY) parts.push(`translate(${(t.motionX ?? 0).toFixed(2)}px, ${(t.motionY ?? 0).toFixed(2)}px)`);\n  parts.push(`rotate(${(t.rotation * DEG).toFixed(3)}deg)`);\n  parts.push(`scale(${(t.scale * (t.scaleX ?? 1)).toFixed(4)}, ${(t.scale * (t.scaleY ?? 1)).toFixed(4)})`);\n  const sx = t.skewX ?? 0, sy = t.skewY ?? 0;\n  if (sx || sy) parts.push(`skew(${(sx * DEG).toFixed(3)}deg, ${(sy * DEG).toFixed(3)}deg)`);\n  return parts.join(' ');\n}\n\n// Apply a pose to a card element. Cards are absolutely centred on the stage.\nexport function applyCardPose(el: HTMLElement, t: BoardTransform, i: number) {\n  el.style.position = 'absolute';\n  el.style.left = '50%';\n  el.style.top = '50%';\n  el.style.margin = '0';\n  el.style.transform = boardTransformCss(t);\n  el.style.opacity = String(t.alpha);\n  el.style.zIndex = String(Math.round(t.depth * 1000 + i));\n}\n",
  "sceneEngine.ts": "// ============================================================\n//  SCENE ENGINE — PURE INTERACTION LAYERS\n//  Interaction logic lives here, fully decoupled from React and the DOM: given\n//  the reduced pointer input and a config, an interaction advances its own\n//  per-card state and returns what each card should render. BoardStage is only a\n//  driver — it feeds input in and applies the output.\n//\n//  This is the seam that lets scenes COMPOSE: each scene is one interaction\n//  layer with its own isolated state, and the final pose is the sum of every\n//  layer's contribution (see boardCompose's \"add deltas, never replace\" rule).\n//  The first layer is the \"book collection\" hover below.\n// ============================================================\n\nimport { loopCycles } from './motion';\n\n// The pointer reduced to what every layer needs: which card is focused (−1 =\n// none) and whether the pointer is still anywhere on the board.\nexport interface SceneInput {\n  focus: number;\n  onBoard: boolean;\n  dt: number; // seconds since the last frame\n}\n\n// Config for the collection layer, re-read each frame from the stores.\nexport interface CollectionCfg {\n  count: number;\n  radius: number;\n  side: 'left' | 'right' | 'both';\n  rampMs: number;   // time a card takes to slide fully open / closed\n  speed: number;    // template steps/sec (sets one step's length in frames)\n  duration: number; // clip seconds\n  fps: number;\n}\n\n// What a single card should render this frame. `slot`/`weight` are the follower\n// slot and intensity captured when the card first opened, so the rich per-card\n// timing survives the focus moving on.\nexport interface CardMotion {\n  frame: number;  // this card's own open progress, in frames\n  slot: number;   // template motionIndex (follower slot, 1..R)\n  weight: number; // template motion intensity (0..1)\n}\n\nexport interface CollectionFrame {\n  cards: CardMotion[];\n  motionCount: number; // template motionCount (the local stack size)\n  motionSign: number;  // push the opened side away from the focus\n}\n\n// The \"book collection\" hover, as a stateful-but-isolated pure layer. Focus F is\n// the card under the pointer, held while the pointer is between books so opened\n// cards STAY; everything on the reveal side of F opens; moving F right opens\n// more, moving F left un-parks, leaving the board collapses it all home.\nexport function createCollectionScene() {\n  let activeIdx = -1;     // focus F, held through the exit\n  let returning = false;  // pointer left the board → collapse home\n  const openF: number[] = []; // per-card open progress (frames)\n  const slot: number[] = [];  // per-card captured follower slot (0 = home/unset)\n  const wgt: number[] = [];   // per-card captured intensity\n  const cards: CardMotion[] = [];\n\n  function reset() {\n    activeIdx = -1;\n    returning = false;\n    openF.length = 0;\n    slot.length = 0;\n    wgt.length = 0;\n    cards.length = 0;\n  }\n\n  function update(input: SceneInput, cfg: CollectionCfg): CollectionFrame {\n    const { focus, onBoard, dt } = input;\n    const { count: n, radius: R, side, rampMs, speed, duration, fps } = cfg;\n\n    const total = Math.max(1, Math.round(duration * fps));\n    // The opened cards form a local stack of up to R+1 slots, so a captured slot\n    // (1..R) maps to a real slot and the template's staggered per-slot timing\n    // survives. capFrame = one full step (one slot advance) in frames.\n    const mCount = Math.max(2, R + 1);\n    const cyc = Math.abs(loopCycles(speed, duration, mCount)) || 1;\n    const capFrame = Math.max(1, Math.ceil(total / cyc) - 1);\n\n    // Focus + return resolution. The focus is held when the pointer is between\n    // books (off a card but still on the board) so the collection persists.\n    if (focus >= 0) { activeIdx = focus; returning = false; }\n    else if (!onBoard) { returning = true; }\n    const F = activeIdx;\n\n    // Frames slid per tick — rampMs sets how long a card takes to open / close.\n    const df = rampMs > 0 ? capFrame * (dt * 1000 / rampMs) : capFrame;\n\n    // Current opened extent (armed = slot captured). New cards may only open on\n    // the LEADING edge — never deeper than the current extent — so moving the\n    // focus back the other way un-parks cards without the R-window re-opening a\n    // fresh deeper one on the far side.\n    let lo = Infinity, hi = -1;\n    for (let i = 0; i < n; i++) if ((slot[i] ?? 0) > 0) { if (i < lo) lo = i; if (i > hi) hi = i; }\n    const hasOpen = hi >= 0;\n\n    for (let i = 0; i < n; i++) {\n      const of = openF[i] ?? 0;\n      const armed = (slot[i] ?? 0) > 0; // already in the open set\n      let tgt = 0;\n      if (!returning && F >= 0) {\n        // Signed distance on the reveal side (>0 = this card opens away from F).\n        const dist = side === 'right' ? i - F : side === 'left' ? F - i : Math.abs(i - F);\n        const onOpenSide = dist >= 1;\n        if (armed) {\n          // Stay open while still on the open side; close when the focus crosses\n          // back past it (un-park).\n          if (onOpenSide) tgt = capFrame;\n        } else if (onOpenSide && dist <= R) {\n          // New open: only on the leading edge. For one-sided reveals, refuse to\n          // open a card deeper than the current extent (that's the \"moving back\"\n          // case — it should only un-park, never open a fresh deeper card).\n          let allow = true;\n          if (hasOpen && side === 'left') allow = i >= lo;\n          else if (hasOpen && side === 'right') allow = i <= hi;\n          if (allow) {\n            tgt = capFrame;\n            // Capture the slot + intensity once, then freeze so the card keeps\n            // its timing when the focus moves on.\n            const s = Math.max(1, Math.min(R, dist));\n            slot[i] = s;\n            wgt[i] = 1 - (s - 1) / (R + 1); // adjacent hardest, fading over R\n          }\n        }\n      }\n      const nf = of < tgt ? Math.min(tgt, of + df) : of > tgt ? Math.max(tgt, of - df) : of;\n      openF[i] = nf <= 0.001 ? 0 : nf;\n      if (openF[i] === 0) { slot[i] = 0; wgt[i] = 0; } // fully home → forget capture\n      cards[i] = {\n        frame: openF[i],\n        slot: Math.max(1, slot[i] ?? 1),\n        weight: openF[i] > 0.01 ? (wgt[i] ?? 0) : 0,\n      };\n    }\n    cards.length = n;\n\n    // Once the collection is fully home, release the focus so re-entering a card\n    // starts a clean open.\n    if (returning) {\n      let any = false;\n      for (let i = 0; i < n; i++) if ((openF[i] ?? 0) > 0.5) { any = true; break; }\n      if (!any) { activeIdx = -1; returning = false; }\n    }\n\n    return { cards, motionCount: mCount, motionSign: side === 'right' ? -1 : 1 };\n  }\n\n  return { update, reset };\n}\n\nexport type CollectionScene = ReturnType<typeof createCollectionScene>;\n\n// ------------------------------------------------------------\n//  SCENE 2 — LIFT (keyed to the focused card)\n// ------------------------------------------------------------\n\nexport interface LiftCfg {\n  count: number;\n  rampMs: number;\n  speed: number;\n  duration: number;\n  fps: number;\n}\n\n// Lifts the card under the pointer (and lowers it as the focus moves on or\n// leaves), so a wave follows the mouse. Fully independent of the collection\n// layer — same input, its own state — and rendered through a Stack-01 template\n// by the driver so it keeps that animation's eased detail.\nexport function createLiftScene() {\n  const liftF: number[] = []; // per-card lift progress in frames\n  const cards: CardMotion[] = [];\n\n  function reset() { liftF.length = 0; cards.length = 0; }\n\n  function update(input: SceneInput, cfg: LiftCfg): CollectionFrame {\n    const { focus, onBoard, dt } = input;\n    const { count: n, rampMs, speed, duration, fps } = cfg;\n\n    const total = Math.max(1, Math.round(duration * fps));\n    const mCount = 2; // a single card doing one follower-slot lift\n    const cyc = Math.abs(loopCycles(speed, duration, mCount)) || 1;\n    const capFrame = Math.max(1, Math.ceil(total / cyc) - 1);\n    const df = rampMs > 0 ? capFrame * (dt * 1000 / rampMs) : capFrame;\n\n    for (let i = 0; i < n; i++) {\n      const tgt = onBoard && focus >= 0 && i === focus ? capFrame : 0;\n      const of = liftF[i] ?? 0;\n      const nf = of < tgt ? Math.min(tgt, of + df) : of > tgt ? Math.max(tgt, of - df) : of;\n      liftF[i] = nf <= 0.001 ? 0 : nf;\n      cards[i] = { frame: liftF[i], slot: 1, weight: liftF[i] > 0.01 ? 1 : 0 };\n    }\n    cards.length = n;\n    return { cards, motionCount: mCount, motionSign: 1 };\n  }\n\n  return { update, reset };\n}\n\nexport type LiftScene = ReturnType<typeof createLiftScene>;\n",
  "variant.ts": "import type { Template } from './types';\n\n// A variant is the same template (controls + transform) shipped with different\n// declared defaults — mirroring the reference tool's \"Wheel 01…06\" presets.\n// Full-reset-on-switch then produces the preset look for free.\nexport function variant(\n  base: Template,\n  id: string,\n  name: string,\n  patch: Record<string, any> = {}\n): Template {\n  return {\n    meta: { ...base.meta, id, name },\n    controls: base.controls.map((c) =>\n      patch[c.key] !== undefined ? { ...c, default: patch[c.key] } : c\n    ),\n    transform: base.transform,\n  };\n}\n",
  "blank.ts": "import type { Template } from './types';\n\nconst BASE = 340;\n\n// Blank — a minimal empty starting canvas: a static, centred grid with no motion.\n// The transform ignores `frame` entirely, giving a still slate to build from.\nconst blank: Template = {\n  meta: { id: 'blank-01', name: 'Canvas 01', group: 'Canvas', defaultEasing: { id: 'linear' } },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 1, max: 12, step: 1,   default: 4 },\n    { key: 'cols',         label: 'Columns',       type: 'slider', min: 1, max: 6, step: 1,    default: 2 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 500, step: 1, default: 220 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 14 },\n    { key: 'gap',          label: 'Gap',           type: 'slider', min: 0, max: 200, step: 1,  default: 40 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, _ctx) => {\n    const sizeFactor = v.cardSize / BASE;\n    const cols = Math.max(1, Math.round(v.cols));\n    const rows = Math.ceil(count / cols);\n    const col = index % cols;\n    const row = Math.floor(index / cols);\n\n    const spacingX = (v.cardSize * 0.8 + v.gap) * sizeFactor;\n    const spacingY = (v.cardSize + v.gap) * sizeFactor;\n    const x = (col - (cols - 1) / 2) * spacingX + v.offset.x;\n    const y = (row - (rows - 1) / 2) * spacingY + v.offset.y;\n\n    return {\n      x,\n      y,\n      scale: sizeFactor,\n      rotation: 0,\n      alpha: 1,\n      depth: index,\n    };\n  },\n};\n\nexport const blankVariants: Template[] = [blank];\n",
  "carousel.ts": "import type { Template } from './types';\nimport { clamp, loopCycles } from './motion';\nimport { cardPath } from './cardPath';\n\n// Reference size (px) shared with the renderer's sprite normalization, so that\n// `cardSize` reads directly in on-screen pixels.\nconst BASE = 340;\n\nexport const carousel: Template = {\n  meta: { id: 'carousel', name: 'Runway', group: 'Runway', defaultEasing: { id: 'glide' } },\n\n  controls: [\n    // Four-way direction (as in the reference tool): left/right run the strip\n    // horizontally, up/down run it vertically. Axis + travel sign in one control.\n    { key: 'direction',    label: 'Direction',     type: 'pills', options: ['left','right','up','down'], default: 'left' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 1, max: 12, step: 1,   default: 6 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 800, step: 1, default: 340 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 12 },\n    { key: 'gap',          label: 'Gap',           type: 'slider', min: 0, max: 600, step: 1,  default: 360 }, // px between card centres (at base size)\n    { key: 'bigScale',     label: 'Big Scale',     type: 'slider', min: 100, max: 200, step: 1, default: 120 }, // featured card size %\n    { key: 'scaleFocus',   label: 'Scale Focus',   type: 'pills', options: ['center','start','end'], default: 'center' }, // where the featured card sits\n    { key: 'perspective',  label: 'Perspective',   type: 'slider', min: 0, max: 200, step: 1,  default: 0 },\n    { key: 'tiltStyle',    label: 'Tilt Style',    type: 'pills', options: ['off','fan','uniform','alternate'], default: 'off' },\n    { key: 'tiltAmount',   label: 'Tilt Amount',   type: 'slider', min: 0, max: 30, step: 1,   default: 8 },   // degrees\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n    { key: 'fade',         label: 'Fade',          type: 'slider', min: 0, max: 100, step: 1,  default: 0 },   // centre-distance fade %\n    { key: 'outerFade',    label: 'Outer Fade',    type: 'slider', min: 0, max: 100, step: 1,  default: 100 }, // fade out while leaving the frame %\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 4, step: 0.1,  default: 0.6 }, // cards/sec\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const horiz = v.direction === 'left' || v.direction === 'right';\n    const dir = (v.direction === 'left' || v.direction === 'up') ? 1 : -1;\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count) * dir); // ← Speed + Direction + Easing\n\n    // Cards recycle seamlessly (wrap). Featuredness peaks at centre.\n    const p = cardPath({ kind: 'line', index, count, phase, gap: 1, wrap: true });\n    const offset = p.x;                                          // gap:1 → x carries the raw signed offset\n    const sizeFactor = v.cardSize / BASE;\n\n    // pos = offset * Gap * (cardSize/BASE) → spacing grows with the card        ← Gap\n    const pos = offset * v.gap * sizeFactor;\n    const x = (horiz ? pos : 0) + v.offset.x;                    // ← Offset X\n    const y = (horiz ? 0 : pos) + v.offset.y;                    // ← Offset Y\n\n    // Scale Focus: shift the featuredness peak toward the entry (start) or\n    // exit (end) side of travel. dir=+1 means cards enter on the positive side.\n    const shift = Math.max(0, count / 2 - 1.5);\n    const focusOff =\n      v.scaleFocus === 'start' ? dir * shift :\n      v.scaleFocus === 'end'   ? -dir * shift : 0;\n    const featured = Math.max(0, 1 - Math.abs(offset - focusOff));\n\n    // Featured card grows toward Big Scale; others sit at 1.0                    ← Big Scale\n    let scale = sizeFactor * (1 + (v.bigScale / 100 - 1) * featured);            // ← Plane Size\n\n    // Tilt Style: fan = tilt ∝ signed centre distance; uniform = constant;\n    // alternate = ±tilt by card parity.                                          ← Tilt\n    const tiltRad = (v.tiltAmount * Math.PI) / 180;\n    const rotation =\n      v.tiltStyle === 'fan'       ? clamp(offset, -3, 3) * tiltRad * 0.5 :\n      v.tiltStyle === 'uniform'   ? tiltRad :\n      v.tiltStyle === 'alternate' ? (index % 2 ? -tiltRad : tiltRad) : 0;\n\n    // Perspective: off-centre cards shrink and skew away from centre, along\n    // the travel axis (skewX for horizontal strips, skewY for vertical).       ← Perspective\n    const persp = v.perspective / 100;\n    scale *= 1 - (1 - p.depthNorm) * 0.35 * persp;\n    const skew = -Math.sign(offset) * (1 - p.depthNorm) * 0.18 * persp;\n\n    // Edge fade                                                                  ← Fade\n    let alpha = 1 - (v.fade / 100) * (1 - p.depthNorm);\n\n    // Outer fade: as the card starts leaving the frame, fade it out — fully     ← Outer Fade\n    // transparent by the time it has fully exited. Axis-aware.\n    const half = (horiz ? ctx.width : ctx.height) / 2;\n    const cardHalf = (v.cardSize * (scale / sizeFactor)) / 2;\n    const axisPos = horiz ? x : y;\n    const leaving = Math.abs(axisPos) - (half - cardHalf);       // >0 once the edge is crossed\n    if (leaving > 0) {\n      const t = Math.min(1, leaving / Math.max(1, cardHalf * 2)); // 1 = fully outside\n      alpha *= 1 - (v.outerFade / 100) * (t * t * (3 - 2 * t));   // smooth falloff\n    }\n\n    return {\n      x,\n      y,\n      scale,\n      rotation,\n      alpha,\n      skewX: horiz ? skew : 0,\n      skewY: horiz ? 0 : skew,\n      depth: p.depthNorm + featured,                             // featured card always wins the draw order\n    };\n    // cornerRadius is applied where the sprite mask is built, not here.          ← Corner Radius\n  },\n};\n",
  "field.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\nconst lerp = (a: number, b: number, t: number) => a + (b - a) * t;\n// Deterministic hash for per-card variety (no Math.random — transform is pure).\nconst h = (k: number) => { const s = Math.sin(k * 127.1 + 1.7) * 43758.5453; return s - Math.floor(s); };\n\n// Field — a starfield: cards scattered through 3D depth drifting toward the\n// camera at constant velocity. Near ones grow large and diverge outward, then\n// recycle from far to near.\nconst field: Template = {\n  meta: { id: 'field-01', name: 'Warp 01', group: 'Warp', defaultEasing: { id: 'linear' }, repeatAssets: true },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 4, max: 40, step: 1,   default: 18 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 20, max: 400, step: 1, default: 140 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 12 },\n    { key: 'spread',       label: 'Spread',        type: 'slider', min: 100, max: 900, step: 1, default: 500 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 3, step: 0.1,  default: 0.6 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const sizeFactor = v.cardSize / BASE;\n\n    // Depth position: 0 (far) → 1 (near), wrapping continuously. The drift\n    // rate (speed·0.15 laps/sec) is loop-locked to whole depth cycles per clip.\n    const laps = loopCycles(v.speed * 0.15, ctx.duration);\n    const zRaw = index / count + (frame / ctx.totalFrames) * laps;\n    const zf = zRaw - Math.floor(zRaw);\n\n    const scale = sizeFactor * lerp(0.15, 1.5, zf * zf);\n\n    // Scatter each card in a fixed direction; it diverges outward as it nears.\n    const ang = h(index) * Math.PI * 2;\n    const rad = 0.15 + h(index + 50) * 0.85;\n    const x = Math.cos(ang) * rad * v.spread * (0.3 + zf) + v.offset.x;\n    const y = Math.sin(ang) * rad * v.spread * (0.3 + zf) + v.offset.y;\n\n    // Fade in when far, fade out as it passes the camera.\n    const alpha = Math.max(0, Math.min(1, zf / 0.15) * Math.min(1, (1 - zf) / 0.1));\n\n    return {\n      x,\n      y,\n      scale,\n      rotation: 0,\n      alpha,\n      depth: zf, // nearer cards draw on top\n    };\n  },\n};\n\nexport const fieldVariants: Template[] = [\n  field, // Field 01 — calm drift\n  variant(field, 'field-02', 'Warp 02', {\n    count: 30, spread: 700, speed: 1.0,\n  }),\n  variant(field, 'field-03', 'Warp 03', {\n    count: 40, spread: 400, speed: 1.6, cardSize: 100,\n  }),\n  variant(field, 'field-04', 'Warp 04', {\n    count: 12, spread: 850, speed: 0.4, cardSize: 220,\n  }),\n];\n",
  "flicker.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Flicker — cards take turns at centre, cross-fading on a cycle. Effect adds\n// a scale pop or a directional drift to the outgoing card (per the reference\n// tool's Pacing / Effect / Drift controls).\nconst flicker: Template = {\n  meta: { id: 'flicker-01', name: 'Pulse 01', group: 'Pulse', defaultEasing: { id: 'linear' } },\n\n  controls: [\n    { key: 'pacing',       label: 'Pacing',        type: 'toggle', options: ['equal','eased'], default: 'equal' },\n    { key: 'effect',       label: 'Effect',        type: 'pills',  options: ['off','scale','drift'], default: 'off' },\n    { key: 'driftDir',     label: 'Drift Dir',     type: 'pills',  options: ['up','down','left','right'], default: 'up' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 2, max: 12, step: 1,   default: 6 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 800, step: 1, default: 420 },\n    { key: 'driftAmount',  label: 'Drift Amount',  type: 'slider', min: 0, max: 200, step: 1,  default: 40 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 10 },\n    { key: 'speed',        label: 'Cycles',        type: 'slider', min: 0.2, max: 6, step: 0.1, default: 1.5 }, // cards/sec\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count));\n\n    // lifecycle w ∈ [0, count): 0 = this card just became active\n    const w = (((phase - index) % count) + count) % count;\n\n    // visibility: full at w=0, crossfades out over one slot; the incoming\n    // neighbour fades in over the same window\n    let vis = Math.max(0, 1 - w) + Math.max(0, 1 - (count - w));\n    vis = Math.min(1, vis);\n    if (v.pacing === 'eased') vis = vis * vis * (3 - 2 * vis); // smoothstep hold\n\n    // outgoing progress 0→1 during the fade window\n    const out = w < 1 ? w : 0;\n\n    let dx = 0, dy = 0, scl = 1;\n    if (v.effect === 'drift') {\n      const d = out * v.driftAmount;\n      if (v.driftDir === 'up') dy = -d;\n      else if (v.driftDir === 'down') dy = d;\n      else if (v.driftDir === 'left') dx = -d;\n      else dx = d;\n    } else if (v.effect === 'scale') {\n      scl = 1 + out * 0.12;\n    }\n\n    return {\n      x: v.offset.x + dx,\n      y: v.offset.y + dy,\n      scale: (v.cardSize / BASE) * scl,\n      rotation: 0,\n      alpha: vis,\n      depth: vis, // active card on top\n    };\n  },\n};\n\nexport const flickerVariants: Template[] = [\n  flicker, // Flicker 01 — clean crossfade\n  variant(flicker, 'flicker-02', 'Pulse 02', {\n    effect: 'drift', driftDir: 'up', driftAmount: 60, pacing: 'eased', speed: 1,\n  }),\n];\n",
  "gallery.ts": "import type { Template } from './types';\nimport { TAU, clamp, frac, lerp, smooth, hash2 } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Gallery — port of Originkit's \"Image Gallery\": tiles continuously spawn,\n// settle on a ring (Blank Area % of the half-diagonal), drift, then vanish.\n// Appear/Disappear pick the travel sense: in-out grows from the rest point\n// and flies outward; out-in flies in from beyond the canvas and shrinks into\n// the centre. Spiral mode replaces the straight radial run with a continuous\n// spiral through the same rest radius. The source spawns DOM tiles on a GSAP\n// clock; here each layer is a respawning slot on a seeded, evenly-staggered\n// lifecycle — same look, but pure, deterministic, and loop-exact.\nconst gallery: Template = {\n  meta: {\n    id: 'canvas-gallery-01', name: 'Gallery 01', group: 'Canvas',\n    defaultEasing: { id: 'linear' }, repeatAssets: true, cardAspect: 1,\n  },\n\n  controls: [\n    { key: 'count',        label: 'Crowd',         type: 'slider', min: 3, max: 30, step: 1,    default: 10 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 500, step: 1,  default: 190 },\n    { key: 'blankArea',    label: 'Blank Area',    type: 'slider', min: 1, max: 100, step: 1,   default: 45 },\n    { key: 'path',         label: 'Path',          type: 'toggle', options: ['straight','spiral'], default: 'straight' },\n    { key: 'spin',         label: 'Spin',          type: 'pills',  options: ['clockwise','anticlockwise','both'], default: 'both' },\n    { key: 'appear',       label: 'Appear',        type: 'toggle', options: ['in-out','out-in'], default: 'out-in' },\n    { key: 'vanish',       label: 'Disappear',     type: 'toggle', options: ['in-out','out-in'], default: 'out-in' },\n    { key: 'appearT',      label: 'Appear Time',   type: 'slider', min: 0.2, max: 4, step: 0.1, default: 2 },\n    { key: 'holdT',        label: 'Hold Time',     type: 'slider', min: 0, max: 4, step: 0.1,   default: 2 },\n    { key: 'exitT',        label: 'Exit Time',     type: 'slider', min: 0.2, max: 4, step: 0.1, default: 1 },\n    { key: 'seed',         label: 'Seed',          type: 'slider', min: 1, max: 999, step: 1,   default: 1 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,   default: 0 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                               default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    // Lifetime from the three time sliders; whole lifecycles per clip so the\n    // loop is exact, layers evenly staggered like the source's spawn pacing.\n    const T = Math.max(0.4, v.appearT + v.holdT + v.exitT);\n    const laps = Math.max(1, Math.round(ctx.duration / T));\n    const p = ctx.easedPhase((frame / ctx.totalFrames) * laps + index / count);\n    const u = frac(p);\n    // Cycle key wraps every `laps` respawns → frame totalFrames ≡ frame 0.\n    const cyc = ((Math.floor(p) % laps) + laps) % laps;\n    const h = (k: number) => hash2(index * 7.31 + cyc * 13.17, v.seed * k);\n\n    const fA = v.appearT / T;\n    const fH = v.holdT / T;\n    const fE = Math.max(0.001, v.exitT / T);\n\n    const halfDiag = Math.hypot(ctx.width, ctx.height) / 2;\n    const grow = v.appear === 'in-out';   // grow from rest point vs fly in\n    const away = v.vanish === 'in-out';   // fly outward vs shrink back in\n\n    // Seeded per-spawn shape: the source's s0/s2/s3 ranges and tile variety.\n    const s0 = lerp(0.1, 0.4, h(2.3));\n    const s2 = lerp(0.7, 1.1, h(3.7));\n    const s3 = lerp(3.0, 4.5, h(4.9));\n    const sizeJ = lerp(0.8, 1.15, h(11.3));\n    const k = (v.cardSize / BASE) * sizeJ;\n\n    let x: number, y: number, sc: number, al: number;\n\n    if (v.path === 'spiral') {\n      // Continuous spiral through the rest radius; fast-slow-fast progression.\n      const R = halfDiag * 1.1;\n      const startA = h(1.1) * TAU;\n      const spin = v.spin === 'clockwise' ? 1\n        : v.spin === 'anticlockwise' ? -1\n        : h(5.3) < 0.5 ? -1 : 1;\n      const turns = lerp(1.2, 2.0, h(9.7));\n      const startR = grow ? 0 : R;\n      const endR = away ? R : 0;\n      const midR = R * (v.blankArea / 100);\n      const mid = [0.45, 0.5, 0.55][Math.min(2, Math.floor(h(7.9) * 3))];\n\n      const uw = clamp(u + Math.sin(u * TAU) * 0.12, 0, 1);\n      const r = uw <= mid\n        ? lerp(startR, midR, uw / mid)\n        : lerp(midR, endR, (uw - mid) / (1 - mid));\n      const a = startA + spin * uw * turns * TAU;\n\n      x = Math.cos(a) * r;\n      y = Math.sin(a) * r;\n      sc = k * (grow ? s2 * uw : s2 * (1 - uw));\n      al = u < fA ? u / fA : u < fA + fH ? 1 : 1 - (u - fA - fH) / fE;\n    } else {\n      // Straight radial run through an anchor on the Blank Area ring.\n      const A = h(1.1) * TAU;\n      const R0 = (v.blankArea / 100) * halfDiag;\n      const entryD = lerp(80, 140, h(6.1));\n      const exitD = lerp(160, 260, h(8.3));\n      const oRest = grow ? entryD : 0;\n      const oExit = oRest + (away ? exitD : -exitD);\n      const exitScale = away ? s3 : 0.08;\n\n      let o: number;\n      if (u < fA) {\n        const t = smooth(u / fA);\n        o = grow ? t * entryD : (1 - t) * entryD * 2.5;\n        sc = grow ? lerp(s0, s2, t) : lerp(s3, s2, t);\n        al = grow ? 1 : t;\n      } else if (u < fA + fH) {\n        // Drift: creep 15% of the way toward the exit target while holding.\n        const t = fH > 0 ? (u - fA) / fH : 1;\n        o = lerp(oRest, oExit, 0.15 * t);\n        sc = lerp(s2, exitScale, 0.15 * t);\n        al = 1;\n      } else {\n        const t = smooth((u - fA - fH) / fE);\n        o = lerp(oRest + (oExit - oRest) * 0.15, oExit, t);\n        sc = lerp(s2 + (exitScale - s2) * 0.15, exitScale, t);\n        al = 1 - t;\n      }\n      sc *= k;\n      x = Math.cos(A) * (R0 + o);\n      y = Math.sin(A) * (R0 + o);\n    }\n\n    return {\n      x: x + v.offset.x,\n      y: y + v.offset.y,\n      scale: Math.max(0.001, sc),\n      rotation: 0,\n      alpha: clamp(al, 0, 1),\n      depth: 1 - u, // newest tile sits on top, like the source's z counter\n    };\n  },\n};\n\nexport const galleryVariants: Template[] = [\n  gallery, // Gallery 01 — the component defaults: fly in, hold, shrink away\n  variant(gallery, 'canvas-gallery-02', 'Gallery 02', {\n    path: 'spiral', appear: 'in-out', appearT: 1.6, holdT: 1, exitT: 1.4, blankArea: 40,\n  }),\n  variant(gallery, 'canvas-gallery-03', 'Gallery 03', {\n    appear: 'in-out', vanish: 'in-out', blankArea: 12, appearT: 0.5, holdT: 0.8,\n    exitT: 0.9, count: 14, cardSize: 150,\n  }),\n];\n",
  "globe.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\nconst lerp = (a: number, b: number, t: number) => a + (b - a) * t;\n\n// Globe — images tiled evenly over a slowly spinning sphere (Fibonacci\n// distribution). Front tiles sit large and opaque; rear tiles shrink and fade.\nconst globe: Template = {\n  meta: { id: 'globe-01', name: 'Globe 01', group: 'Globe', defaultEasing: { id: 'linear' } },\n\n  controls: [\n    { key: 'direction',    label: 'Direction',     type: 'toggle', options: ['forward','reverse'], default: 'forward' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 6, max: 60, step: 1,   default: 36 },\n    { key: 'radius',       label: 'Radius',        type: 'slider', min: 100, max: 700, step: 1, default: 420 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 20, max: 300, step: 1, default: 120 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 12 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 3, step: 0.1,  default: 0.4 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const dir = v.direction === 'reverse' ? -1 : 1;\n    // Revolutions per clip, loop-locked to a whole number (lon has period t=1).\n    const t = (frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration) * dir;\n    const sizeFactor = v.cardSize / BASE;\n\n    // Fibonacci sphere: even latitude bands, golden-angle longitude + spin.\n    const gold = Math.PI * (3 - Math.sqrt(5));\n    const lat = Math.asin(-1 + 2 * (index + 0.5) / count);\n    const lon = index * gold + t * Math.PI * 2;\n\n    const cx = Math.cos(lat) * Math.sin(lon);\n    const cz = Math.cos(lat) * Math.cos(lon);\n    const cy = Math.sin(lat);\n\n    const x = cx * v.radius + v.offset.x;\n    const y = cy * v.radius + v.offset.y;\n    const depthN = (cz + 1) / 2; // 1 = front, 0 = back\n\n    const scale = sizeFactor * lerp(0.3, 1.15, depthN);\n    const alpha = lerp(0.12, 1, depthN);\n\n    return {\n      x,\n      y,\n      scale,\n      rotation: 0,\n      alpha,\n      depth: depthN,\n    };\n  },\n};\n\nexport const globeVariants: Template[] = [\n  globe, // Globe 01 — full sphere\n  variant(globe, 'globe-02', 'Globe 02', {\n    count: 24, radius: 300, cardSize: 150,\n  }),\n  variant(globe, 'globe-03', 'Globe 03', {\n    count: 60, radius: 560, cardSize: 90,\n  }),\n  variant(globe, 'globe-04', 'Globe 04', {\n    count: 48, radius: 680, cardSize: 110, speed: 0.7,\n  }),\n];\n",
  "gravity.ts": "import type { Template } from './types';\nimport { variant } from './variant';\n\nconst BASE = 340;\nconst lerp = (a: number, b: number, t: number) => a + (b - a) * t;\nconst clamp = (x: number, lo: number, hi: number) => Math.max(lo, Math.min(hi, x));\n// Deterministic hash for per-card variety (no Math.random — transform is pure).\nconst h = (k: number) => { const s = Math.sin(k * 127.1 + 1.7) * 43758.5453; return s - Math.floor(s); };\n\n// Closed-form bouncing-ball height ABOVE the floor at elapsed time `tau`, for a\n// drop of height H under gravity g with restitution e. Purely analytic (no\n// per-frame integration): walk successive parabolic arcs until we find the one\n// containing `tau`. Guards keep it finite when g≈0 or e≈0.\n//   t0 = sqrt(2H/g)             time to first impact\n//   v0 = sqrt(2gH) = g·t0       impact speed\n//   arc k (k≥1) takeoff speed u_k = v0·e^k, flight time T_k = 2·u_k/g\n//   settles at t_total = t0 + (2v0/g)·e/(1-e)  → height 0 thereafter\nfunction bounceHeight(tau: number, H: number, g: number, e: number): number {\n  if (tau <= 0) return H;                 // still parked at the drop point\n  if (H <= 0 || g <= 1e-6) return 0;      // degenerate: treat as settled\n  const t0 = Math.sqrt((2 * H) / g);\n  if (tau < t0) return H - 0.5 * g * tau * tau;   // initial free fall\n  const v0 = g * t0;\n  const rest = clamp(e, 0, 0.999);        // e<1 guarantees the series converges\n  let rem = tau - t0;\n  let u = v0 * rest;                       // takeoff speed of the first bounce\n  for (let k = 0; k < 40; k++) {\n    const T = (2 * u) / g;                 // flight time of this arc\n    if (T < 1e-4) break;                   // arcs collapsed → settled\n    if (rem < T) return u * rem - 0.5 * g * rem * rem;\n    rem -= T;\n    u *= rest;                             // next arc peaks lower\n  }\n  return 0;                                // energy spent → resting on floor\n}\n\n// Gravity — cards drop from above, tumble as they fall, bounce with restitution\n// and settle into a pile of columns at the bottom. Everything is a pure function\n// of `frame` via a closed-form bounce (no iterative sim reading prior frames).\nconst gravity: Template = {\n  meta: { id: 'gravity-01', name: 'Bounce 01', group: 'Bounce', defaultEasing: { id: 'linear' } },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 2, max: 14, step: 1,     default: 8 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 400, step: 1,   default: 200 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,    default: 12 },\n    { key: 'gravity',      label: 'Gravity',       type: 'slider', min: 0.2, max: 3, step: 0.1,  default: 1 },\n    { key: 'bounce',       label: 'Bounce',        type: 'slider', min: 0, max: 0.9, step: 0.05, default: 0.2 },\n    { key: 'friction',     label: 'Friction',      type: 'slider', min: 0, max: 1, step: 0.05,   default: 0.4 },\n    { key: 'stagger',      label: 'Stagger',       type: 'slider', min: 0, max: 0.6, step: 0.02, default: 0.18 },\n    { key: 'spread',       label: 'Spread',        type: 'slider', min: 100, max: 800, step: 1,  default: 500 },\n    { key: 'spin',         label: 'Spin',          type: 'slider', min: 0, max: 3, step: 0.1,    default: 1 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                                default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const T = frame / ctx.fps; // non-looping by design — physics drop settles and rests\n    const sizeFactor = v.cardSize / BASE;\n    const cardPx = v.cardSize * sizeFactor;     // scaled footprint used for spacing\n\n    // ---- Pile geometry: hash each card into a column, stack shared columns ----\n    const numCols = Math.max(1, Math.min(6, Math.round(v.spread / Math.max(1, cardPx))));\n    const colOf = (i: number) => Math.min(numCols - 1, Math.floor(h(i + 3) * numCols));\n    const col = colOf(index);\n    const columnX = -v.spread / 2 + (col + 0.5) * (v.spread / numCols);\n\n    // How many earlier cards already occupy this column → this card rests on top.\n    let pileRow = 0;\n    for (let j = 0; j < index; j++) if (colOf(j) === col) pileRow++;\n\n    const floorY = ctx.height / 2 - cardPx * 0.5;      // bottom resting band\n    const restY = floorY - pileRow * (cardPx * 0.35);  // stack upward per row\n\n    // ---- Spawn point (above the top edge) and drop height ----\n    const margin = cardPx;\n    const spawnY = -ctx.height / 2 - margin;\n    const spawnX = columnX + (h(index + 7) - 0.5) * v.spread * 0.3;\n    const H = restY - spawnY;                            // > 0 by construction\n\n    // ---- Timeline: per-card stagger, then analytic bounce ----\n    const start = index * v.stagger;\n    const tau = T - start;\n\n    if (tau < 0) {\n      // Not yet released: park just above the top, hidden.\n      return { x: spawnX + v.offset.x, y: spawnY + v.offset.y, scale: sizeFactor, rotation: 0, alpha: 0, depth: index };\n    }\n\n    const g = v.gravity * 2000;                          // px/s^2\n    const e = v.bounce;\n    // Total flight time until the card is at rest (see bounceHeight for series).\n    const t0 = g > 1e-6 && H > 0 ? Math.sqrt((2 * H) / g) : 0;\n    const v0 = g * t0;\n    const eC = clamp(e, 0, 0.999);\n    const tTotal = t0 + (g > 1e-6 ? (2 * v0) / g * (eC / (1 - eC)) : 0);\n\n    const above = bounceHeight(tau, H, g, e);\n    const y = restY - above;                             // up is negative y\n\n    // ---- Horizontal: drift while airborne, damped by friction, then settle ----\n    const driftVx = (h(index + 11) - 0.5) * 500 * (1 - v.friction);\n    const airX = spawnX + driftVx * Math.min(tau, tTotal);\n    const settle = tTotal > 1e-6 ? clamp(tau / tTotal, 0, 1) : 1;\n    const settle2 = settle * settle;                     // ease toward the column\n    const x = clamp(lerp(airX, columnX, settle2), -ctx.width / 2, ctx.width / 2);\n\n    // ---- Rotation: tumble in the air, relax to a slight resting tilt ----\n    const spinDir = h(index + 17) < 0.5 ? -1 : 1;\n    const spinSpeed = v.spin * 4;                        // rad/s at spin=1\n    const airRot = spinDir * spinSpeed * Math.min(tau, tTotal);\n    const restTilt = (h(index + 13) - 0.5) * 0.25;       // small ±0.125 rad\n    const rotation = lerp(airRot, restTilt, settle2);\n\n    return {\n      x: x + v.offset.x,\n      y: y + v.offset.y,\n      scale: sizeFactor,\n      rotation,\n      alpha: 1,\n      depth: index,                                      // later cards land on top\n    };\n    // cornerRadius is applied where the sprite mask is built, not here.\n  },\n};\n\nexport const gravityVariants: Template[] = [\n  gravity, // Gravity 01 — a measured drop with a soft bounce\n  variant(gravity, 'gravity-02', 'Bounce 02', {\n    // Bouncy: springy restitution, little friction, tight fast stagger.\n    bounce: 0.7, friction: 0.1, spin: 1.6, stagger: 0.1, spread: 600,\n  }),\n  variant(gravity, 'gravity-03', 'Bounce 03', {\n    // Slow-mo: low gravity, gentle spin, wide lazy scatter.\n    gravity: 0.35, bounce: 0.3, friction: 0.5, spin: 0.5, stagger: 0.3, cardSize: 160,\n  }),\n];\n",
  "orbit.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Orbit — cards circle an ellipse; the front-most card grows and passes in\n// front, then recedes behind. Flat ellipses read as a side-pass conveyor.\nconst orbit: Template = {\n  meta: { id: 'orbit-01', name: 'Orbit 01', group: 'Orbit', defaultEasing: { id: 'flow' } },\n\n  controls: [\n    { key: 'direction',    label: 'Direction',     type: 'toggle', options: ['forward','reverse'], default: 'forward' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 2, max: 12, step: 1,   default: 4 },\n    { key: 'radiusX',      label: 'Radius X',      type: 'slider', min: 0, max: 700, step: 1,  default: 330 },\n    { key: 'radiusY',      label: 'Radius Y',      type: 'slider', min: 0, max: 700, step: 1,  default: 40 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 800, step: 1, default: 330 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 8 },\n    { key: 'bigScale',     label: 'Big Scale',     type: 'slider', min: 100, max: 220, step: 1, default: 140 },\n    { key: 'depthShrink',  label: 'Depth Shrink',  type: 'slider', min: 0, max: 90, step: 1,   default: 45 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 4, step: 0.1,  default: 0.3 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n    { key: 'fade',         label: 'Fade',          type: 'slider', min: 0, max: 100, step: 1,  default: 25 },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const dir = v.direction === 'reverse' ? -1 : 1;\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count) * dir);\n    const ang = ((index - phase) / count) * Math.PI * 2;\n\n    const x = Math.sin(ang) * v.radiusX;\n    const y = Math.cos(ang) * v.radiusY;            // front card sits slightly low\n    const depthNorm = (Math.cos(ang) + 1) / 2;      // 1 = front, 0 = back\n\n    // front-most pop: only the nearest-to-front card grows toward Big Scale\n    const featured = Math.max(0, depthNorm * 2 - 1);\n    const shrink = 1 - (v.depthShrink / 100) * (1 - depthNorm);\n    const scale = (v.cardSize / BASE) * shrink * (1 + (v.bigScale / 100 - 1) * featured);\n\n    const alpha = 1 - (v.fade / 100) * (1 - depthNorm);\n\n    return {\n      x: x + v.offset.x,\n      y: y + v.offset.y,\n      scale,\n      rotation: 0,\n      alpha,\n      depth: depthNorm,\n    };\n  },\n};\n\nexport const orbitVariants: Template[] = [\n  orbit, // Orbit 01 — flat side pass\n  variant(orbit, 'orbit-02', 'Orbit 02', {\n    radiusX: 40, radiusY: 300, count: 3, bigScale: 150, speed: 0.25,\n  }),\n  variant(orbit, 'orbit-03', 'Orbit 03', {\n    radiusX: 300, radiusY: 300, count: 8, cardSize: 150, bigScale: 110,\n    depthShrink: 25, fade: 10, speed: 0.5,\n  }),\n];\n",
  "orbit3d.ts": "import type { Template } from './types';\nimport { TAU, lerp, loopCycles } from './motion';\nimport { cardPath } from './cardPath';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Orbit 3D — real WebGL orbit: cards ride a circle in actual 3D space, seen\n// through a perspective camera (the `perspective` control maps to camera FOV\n// in the 3D renderer). `facing` chooses billboarded cards (screen) or cards\n// lying on the ring like a carousel drum (ring). The 2D transform below is a\n// cheap projection of the same motion for thumbnails.\nconst orbit3d: Template = {\n  meta: {\n    id: 'orbit-3d-01', name: 'Orbit 3D 01', group: 'Orbit',\n    defaultEasing: { id: 'flow' }, engine: 'webgl',\n  },\n\n  controls: [\n    { key: 'direction',   label: 'Direction',   type: 'toggle', options: ['forward','reverse'], default: 'forward' },\n    { key: 'count',       label: 'Count',       type: 'slider', min: 2, max: 16, step: 1,   default: 8 },\n    { key: 'cardSize',    label: 'Plane Size',  type: 'slider', min: 50, max: 800, step: 1, default: 300 },\n    { key: 'radius',      label: 'Orbit Radius',type: 'slider', min: 100, max: 700, step: 1, default: 380 },\n    { key: 'perspective', label: 'Perspective', type: 'slider', min: 0, max: 200, step: 1,  default: 120 },\n    { key: 'tiltX',       label: 'Tilt',        type: 'slider', min: -45, max: 45, step: 1, default: 10 },\n    { key: 'facing',      label: 'Facing',      type: 'pills', options: ['screen','ring'],  default: 'screen' },\n    { key: 'fade',        label: 'Depth Fade',  type: 'slider', min: 0, max: 100, step: 1,  default: 25 },\n    { key: 'speed',       label: 'Speed',       type: 'slider', min: 0, max: 2, step: 0.1,  default: 0.3 },\n    { key: 'offset',      label: 'Offset',      type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  // Real 3D pose (renderer3d). y is canvas-down; the renderer flips it.\n  transform3d: (frame, index, count, v, ctx) => {\n    const dir = v.direction === 'reverse' ? -1 : 1;\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count) * dir);\n    const a = TAU * ((index - phase) / count);\n\n    // ring in the XZ plane, tilted around the X axis\n    const tilt = (v.tiltX * Math.PI) / 180;\n    const x0 = Math.sin(a) * v.radius;\n    const z0 = Math.cos(a) * v.radius;\n    const y = -z0 * Math.sin(tilt) + v.offset.y; // tilt lifts the far side\n    const z = z0 * Math.cos(tilt);\n\n    const depthN = (z0 / v.radius + 1) / 2; // 1 = front, 0 = back\n    const alpha = 1 - (v.fade / 100) * (1 - depthN);\n\n    return {\n      x: x0 + v.offset.x,\n      y,\n      z,\n      rotationX: v.facing === 'ring' ? tilt : 0,\n      rotationY: v.facing === 'ring' ? a : 0,\n      rotationZ: 0,\n      scale: v.cardSize / BASE,\n      alpha,\n    };\n  },\n\n  // 2D projection of the same orbit (thumbnails + non-webgl fallback).\n  transform: (frame, index, count, v, ctx) => {\n    const dir = v.direction === 'reverse' ? -1 : 1;\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count) * dir);\n    const p = cardPath({ kind: 'ring', index, count, phase, radius: v.radius });\n    const tiltSquash = Math.abs(Math.sin((v.tiltX * Math.PI) / 180)) * 0.8 + 0.1;\n    const scale = (v.cardSize / BASE) * lerp(0.55, 1.1, p.depthNorm);\n    return {\n      x: p.x + v.offset.x,\n      y: -p.y * tiltSquash + v.offset.y,\n      scale,\n      rotation: 0,\n      alpha: 1 - (v.fade / 100) * (1 - p.depthNorm),\n      depth: p.depthNorm,\n    };\n  },\n};\n\nexport const orbit3dVariants: Template[] = [\n  orbit3d,\n  variant(orbit3d, 'orbit-3d-02', 'Orbit 3D 02', {\n    facing: 'ring', count: 10, radius: 460, tiltX: 0, perspective: 160, speed: 0.25,\n  }),\n  variant(orbit3d, 'orbit-3d-03', 'Orbit 3D 03', {\n    count: 6, radius: 300, tiltX: 28, perspective: 80, cardSize: 380, fade: 45,\n  }),\n];\n",
  "parallax.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\n// Parallax — a multi-layer image wall with depth. The camera pans\n// horizontally while near layers travel faster than far ones, and cards\n// wrap seamlessly across the field.\nconst BASE = 340;\nconst lerp = (a: number, b: number, t: number) => a + (b - a) * t;\nconst h = (k: number) => { const s = Math.sin(k * 127.1 + 1.7) * 43758.5453; return s - Math.floor(s); };\n\nconst parallax: Template = {\n  meta: { id: 'parallax-01', name: 'Drift 01', group: 'Drift', defaultEasing: { id: 'smooth' } },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 3, max: 16, step: 1,    default: 9 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 500, step: 1,  default: 220 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,   default: 14 },\n    { key: 'gap',          label: 'Gap',           type: 'slider', min: 80, max: 500, step: 1,  default: 260 },\n    { key: 'spreadY',      label: 'Spread Y',      type: 'slider', min: 0, max: 600, step: 1,   default: 260 },\n    { key: 'scatter',      label: 'Scatter',       type: 'slider', min: 0, max: 300, step: 1,   default: 80 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 3, step: 0.1,   default: 0.5 },\n    { key: 'direction',    label: 'Direction',     type: 'toggle', options: ['forward','reverse'], default: 'forward' },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                               default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const sizeFactor = v.cardSize / BASE;\n\n    // 0 = far, 1 = near\n    const layer = count <= 1 ? 1 : index / (count - 1);\n    const depthScale = lerp(0.5, 1.35, layer);\n    const pSpeed = lerp(0.25, 1, layer); // near layers scroll faster\n\n    const dir = v.direction === 'reverse' ? -1 : 1;\n\n    // horizontal scatter + scroll, wrapped across the field span. Each layer\n    // scrolls at its own depth-proportional rate, so each card's wrap count is\n    // quantized separately — every card returns exactly at the loop point.\n    const span = count * v.gap * sizeFactor;\n    const wraps = Math.max(1, Math.round((v.speed * ctx.duration * ctx.width * pSpeed) / span));\n    const t = ctx.easedPhase((frame / ctx.totalFrames) * wraps) * dir;\n    const raw = index * v.gap * sizeFactor - t * span;\n    const x = (((raw % span) + span) % span) - span / 2 + v.offset.x;\n\n    // vertical placement by layer with a little deterministic scatter\n    const y = (layer - 0.5) * v.spreadY + (h(index) - 0.5) * v.scatter + v.offset.y;\n\n    return {\n      x,\n      y,\n      scale: sizeFactor * depthScale,\n      rotation: 0,\n      alpha: lerp(0.55, 1, layer),\n      depth: layer,\n    };\n  },\n};\n\nexport const parallaxVariants: Template[] = [\n  parallax,\n  variant(parallax, 'parallax-02', 'Drift 02', { count: 12, spreadY: 380, speed: 0.8 }),\n  variant(parallax, 'parallax-03', 'Drift 03', { count: 6, spreadY: 140, speed: 0.35 }),\n  variant(parallax, 'parallax-04', 'Drift 04', { count: 16, spreadY: 460, speed: 1.1 }),\n];\n",
  "proximity.ts": "import type { Template } from './types';\nimport { TAU, frac, wave, clamp, lerp, hash2, loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Proximity — a dense grid of small tiles; a focus point pans across and the\n// tiles nearest it magnify (macOS-dock style), while distant ones stay small\n// and fade slightly. The focal path is selectable; sizeMix/tilt add per-tile\n// variety; atmosphere adds a distance haze; buildInOut ramps the whole field.\nconst proximity: Template = {\n  meta: { id: 'proximity-01', name: 'Dock 01', group: 'Dock', defaultEasing: { id: 'flow' }, repeatAssets: true },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 6, max: 200, step: 1,  default: 30 },\n    { key: 'cols',         label: 'Columns',       type: 'slider', min: 3, max: 16, step: 1,   default: 6 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 20, max: 200, step: 1, default: 90 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 12 },\n    { key: 'gap',          label: 'Gap',           type: 'slider', min: 0, max: 80, step: 1,   default: 12 },\n    { key: 'magnify',      label: 'Magnify',       type: 'slider', min: 0, max: 2, step: 0.05, default: 1 },\n    { key: 'focusRadius',  label: 'Focus Radius',  type: 'slider', min: 80, max: 600, step: 1, default: 260 },\n    { key: 'path',         label: 'Focal Path',    type: 'select', options: ['lissajous','sweep','diagonal','figure8'], default: 'lissajous' },\n    { key: 'sizeMix',      label: 'Size Mix',      type: 'slider', min: 0, max: 100, step: 1,  default: 0 },\n    { key: 'tilt',         label: 'Tilt',          type: 'slider', min: 0, max: 45, step: 1,   default: 0 },\n    { key: 'atmosphere',   label: 'Atmosphere',    type: 'slider', min: 0, max: 100, step: 1,  default: 0 },\n    { key: 'buildInOut',   label: 'Build In/Out',  type: 'toggle', options: ['on','off'],      default: 'off' },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 3, step: 0.1,  default: 0.6 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const sizeFactor = v.cardSize / BASE;\n\n    // Grid layout centred on the canvas.\n    const cols = Math.max(1, Math.round(v.cols));\n    const rows = Math.ceil(count / cols);\n    const col = index % cols;\n    const row = Math.floor(index / cols);\n\n    const spacingX = (v.cardSize + v.gap) * sizeFactor;\n    const spacingY = (v.cardSize + v.gap) * sizeFactor;\n    const baseX = (col - (cols - 1) / 2) * spacingX;\n    const baseY = (row - (rows - 1) / 2) * spacingY;\n\n    // Focus point pans on a selectable, loop-locked path (whole revolutions\n    // per clip; integer-ratio Lissajous frequencies so every path closes).\n    const th = TAU * frac((frame / ctx.totalFrames) * loopCycles(v.speed * 0.15, ctx.duration));\n    const ampX = cols * spacingX * 0.35;\n    const ampY = rows * spacingY * 0.35;\n    let fx = 0, fy = 0;\n    switch (v.path) {\n      case 'sweep':    fx = Math.sin(th) * ampX; fy = 0; break;\n      case 'diagonal': fx = Math.sin(th) * ampX; fy = Math.sin(th) * ampY; break;\n      case 'figure8':  fx = Math.sin(th) * ampX; fy = Math.sin(2 * th) * ampY * 0.5; break;\n      default:         fx = Math.sin(2 * th) * ampX; fy = Math.cos(3 * th) * ampY; // lissajous 2:3\n    }\n\n    const dist = Math.hypot(baseX - fx, baseY - fy);\n    const r = v.focusRadius;\n    const mag = 1 + v.magnify * Math.max(0, 1 - dist / r);\n\n    // per-tile variety: deterministic size mix and rotation wobble\n    const mix = 1 - (v.sizeMix / 100) * 0.6 * hash2(index, 13.7);\n    const rotation = ((hash2(index, 71.3) - 0.5) * 2 * v.tilt * Math.PI) / 180;\n\n    // whole-field build in/out envelope (0 at both ends → loop-safe)\n    const env = v.buildInOut === 'on' ? Math.pow(wave(frame / ctx.totalFrames), 0.75) : 1;\n\n    const scale = sizeFactor * mag * mix * env;\n    let alpha = lerp(0.45, 1, Math.max(0, 1 - dist / (r * 1.6)));\n    alpha *= 1 - (v.atmosphere / 100) * clamp(dist / (r * 2), 0, 1); // distance haze\n\n    return {\n      x: baseX + v.offset.x,\n      y: baseY + v.offset.y,\n      scale,\n      rotation,\n      alpha,\n      depth: mag, // magnified tiles draw on top of their neighbours\n    };\n  },\n};\n\nexport const proximityVariants: Template[] = [\n  proximity, // Proximity 01 — 6-wide dock\n  variant(proximity, 'proximity-02', 'Dock 02', {\n    cols: 8, count: 40, magnify: 1.4,\n  }),\n  variant(proximity, 'proximity-03', 'Dock 03', {\n    cols: 4, count: 20, magnify: 0.8, cardSize: 120,\n  }),\n  variant(proximity, 'proximity-04', 'Dock 04', {\n    cols: 10, count: 60, magnify: 1.8, cardSize: 70, focusRadius: 340,\n  }),\n  variant(proximity, 'proximity-05', 'Dock 05', {\n    path: 'figure8', cols: 12, count: 96, cardSize: 64, gap: 8, magnify: 1.6, sizeMix: 35, atmosphere: 30,\n  }),\n  variant(proximity, 'proximity-06', 'Dock 06', {\n    path: 'sweep', buildInOut: 'on', cols: 14, count: 140, cardSize: 48, gap: 6, magnify: 1.2, tilt: 12, atmosphere: 45,\n  }),\n];\n",
  "reveal.ts": "import type { Template } from './types';\nimport { smooth, clamp } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\nconst TEX_RATIO = 480 / 600; // house placeholder/texture proportion\n\n// Frames Reveal — editorial magazine panels revealed one-by-one with a sweep,\n// held, then swept out in reverse so the clip loops cleanly (frame 0 ≡ frame N:\n// both fully empty). Layouts are pure data: panel rects in normalized canvas\n// fractions (centre origin), ordered by reveal row.\ninterface Panel { x: number; y: number; w: number; h: number; row: number }\n\nconst LAYOUTS: Record<string, Panel[]> = {\n  splitTop: [\n    { x: 0, y: -0.22, w: 0.90, h: 0.50, row: 0 },\n    { x: -0.235, y: 0.28, w: 0.43, h: 0.42, row: 1 },\n    { x: 0.235, y: 0.28, w: 0.43, h: 0.42, row: 1 },\n  ],\n  thirds: [\n    { x: -0.28, y: 0, w: 0.38, h: 0.92, row: 0 },\n    { x: 0.20, y: -0.24, w: 0.52, h: 0.42, row: 1 },\n    { x: 0.20, y: 0.24, w: 0.52, h: 0.42, row: 2 },\n  ],\n  grid6: [\n    { x: -0.235, y: -0.31, w: 0.43, h: 0.28, row: 0 },\n    { x: 0.235, y: -0.31, w: 0.43, h: 0.28, row: 0 },\n    { x: -0.235, y: 0, w: 0.43, h: 0.28, row: 1 },\n    { x: 0.235, y: 0, w: 0.43, h: 0.28, row: 1 },\n    { x: -0.235, y: 0.31, w: 0.43, h: 0.28, row: 2 },\n    { x: 0.235, y: 0.31, w: 0.43, h: 0.28, row: 2 },\n  ],\n  columns: [\n    { x: -0.235, y: 0, w: 0.43, h: 0.92, row: 0 },\n    { x: 0.235, y: 0, w: 0.43, h: 0.92, row: 1 },\n  ],\n};\n\nconst reveal: Template = {\n  meta: {\n    id: 'frames-05', name: 'Editorial Reveal', group: 'Editorial',\n    defaultEasing: { id: 'flow' }, repeatAssets: true,\n  },\n\n  controls: [\n    { key: 'layout',       label: 'Layout',        type: 'select', options: ['splitTop','thirds','grid6','columns'], default: 'splitTop' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 2, max: 6, step: 1,    default: 6 },\n    { key: 'sweep',        label: 'Sweep',         type: 'slider', min: 20, max: 90, step: 1,  default: 40 },  // % of the clip spent revealing + hiding\n    { key: 'rowsSkipped',  label: 'Rows Skipped',  type: 'slider', min: 0, max: 2, step: 1,    default: 0 },   // interleave reveal rows per pass\n    { key: 'gap',          label: 'Inset',         type: 'slider', min: 50, max: 130, step: 1, default: 100 }, // panel size %\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 0 },\n    { key: 'tilt',         label: 'Tilt',          type: 'slider', min: -15, max: 15, step: 0.5, default: 0 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const panels = LAYOUTS[v.layout] ?? LAYOUTS.splitTop;\n    const panel = panels[index];\n    if (!panel) return { x: 0, y: 0, scale: 0, rotation: 0, alpha: 0, depth: -1 }; // unused slot\n\n    // ---- reveal order: rows interleaved by rowsSkipped ----\n    const rows = Math.max(...panels.map((p) => p.row)) + 1;\n    const skip = Math.min(Math.round(v.rowsSkipped), Math.max(0, rows - 1)) + 1;\n    // pass ordering: rows 0, skip, 2*skip, …, then 1, 1+skip, …\n    const rowRank: number[] = new Array(rows).fill(0);\n    let rank = 0;\n    for (let start = 0; start < skip; start++)\n      for (let r = start; r < rows; r += skip) rowRank[r] = rank++;\n    const order = panels\n      .map((p, i) => ({ i, key: rowRank[p.row] * 100 + p.x }))\n      .sort((a, b) => a.key - b.key)\n      .findIndex((o) => o.i === index);\n    const n = panels.length;\n\n    // ---- loop-safe timeline: sweep in → hold → sweep out (reverse order) ----\n    const tn = frame / ctx.totalFrames;\n    const half = clamp(v.sweep / 100, 0.2, 0.9) / 2; // each sweep's share of the clip\n    const win = 1.5 / n;                              // per-panel ramp width within a sweep\n\n    let vis: number;\n    if (tn < half) {\n      const p = ctx.ease(tn / half) * (1 + win);      // 0..1+win across the in-sweep\n      vis = smooth((p - order / n) / win);\n    } else if (tn > 1 - half) {\n      const p = ctx.ease((1 - tn) / half) * (1 + win); // mirror: reverse reveal\n      vis = smooth((p - (n - 1 - order) / n) / win);\n    } else {\n      vis = 1;                                        // hold — fully assembled\n    }\n\n    // ---- panel geometry (normalized → px, squashed to the panel's aspect) ----\n    const inset = v.gap / 100;\n    const pw = panel.w * ctx.width * inset;\n    const ph = panel.h * ctx.height * inset;\n    // base sprite is BASE px on its long edge with TEX_RATIO width:height\n    const scale = ph / BASE;\n    const scaleX = (pw / ph) / TEX_RATIO;\n\n    return {\n      x: panel.x * ctx.width + v.offset.x,\n      y: panel.y * ctx.height + v.offset.y,\n      scale: scale * (0.94 + 0.06 * vis),             // slight settle as it lands\n      scaleX,\n      rotation: (v.tilt * Math.PI) / 180,\n      alpha: vis,\n      depth: order,\n    };\n  },\n};\n\nexport const revealVariants: Template[] = [\n  reveal,\n  variant(reveal, 'frames-06', 'Editorial Reveal 02', { layout: 'grid6', sweep: 55, rowsSkipped: 1 }),\n  variant(reveal, 'frames-07', 'Editorial Reveal 03', { layout: 'thirds', sweep: 35, tilt: -4 }),\n  variant(reveal, 'frames-08', 'Editorial Reveal 04', { layout: 'columns', sweep: 50, cornerRadius: 10 }),\n];\n",
  "scale.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\n// Scale — a Ken-Burns zoom slideshow. One image at a time pushes IN (or\n// pulls OUT) from a chosen anchor, cross-fading to the next with a stagger,\n// plus an optional slight spin. The custom expo-out curve gives an instant\n// fast start and a long deceleration.\nconst BASE = 340;\nconst lerp = (a: number, b: number, t: number) => a + (b - a) * t;\n\nconst scale: Template = {\n  meta: { id: 'scale-01', name: 'Dive 01', group: 'Dive', defaultEasing: { id: 'custom', bezier: [0, 0, 0, 0.99] }, cardAspect: 'canvas' },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 2, max: 10, step: 1,    default: 5 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 600, step: 1,  default: 340 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,   default: 0 },\n    { key: 'zoom',         label: 'Zoom',          type: 'slider', min: 0, max: 80, step: 1,    default: 30 },\n    { key: 'direction',    label: 'Direction',     type: 'pills',  options: ['in','out'],       default: 'in' },\n    { key: 'anchor',       label: 'Anchor',        type: 'pills',  options: ['center','tl','tr','bl','br'], default: 'center' },\n    { key: 'spin',         label: 'Spin',          type: 'toggle', options: ['on','off'],       default: 'off' },\n    { key: 'spinAmt',      label: 'Spin Amount',   type: 'slider', min: 0, max: 30, step: 1,    default: 6 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0.2, max: 3, step: 0.1, default: 0.5 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                               default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const sizeFactor = v.cardSize / BASE;\n\n    // lifecycle w ∈ [0, count): 0 = this card just became active.\n    // Period is `count` phase units — loop-lock to whole lifecycle laps.\n    const phase = (frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count);\n    const w = (((phase - index) % count) + count) % count;\n\n    // crossfade over one slot at each end\n    let vis = Math.max(0, 1 - w) + Math.max(0, 1 - (count - w));\n    vis = Math.min(1, vis);\n\n    // eased zoom progress across the active card's visible cycle\n    const age = w / count; // 0 → 1 while this is the current image\n    const z = ctx.ease(age);\n\n    const zoomAmt = v.zoom / 100;\n    const s = v.direction === 'out' ? lerp(1 + zoomAmt, 1, z) : lerp(1, 1 + zoomAmt, z);\n    // near full-frame Ken-Burns fit\n    const scl = sizeFactor * (ctx.height / BASE) * 0.9 * s;\n\n    // anchor pan: shift toward the chosen corner as it zooms\n    const ax = v.anchor.includes('l') ? -1 : v.anchor.includes('r') ? 1 : 0;\n    const ay = v.anchor.startsWith('t') ? -1 : v.anchor.startsWith('b') ? 1 : 0;\n    const x = -ax * (s - 1) * v.cardSize * 0.6 + v.offset.x;\n    const y = -ay * (s - 1) * v.cardSize * 0.6 + v.offset.y;\n\n    const rotation = v.spin === 'on' ? (z - 0.5) * (v.spinAmt * Math.PI / 180) : 0;\n\n    return {\n      x,\n      y,\n      scale: scl,\n      rotation,\n      alpha: vis,\n      depth: vis,\n    };\n  },\n};\n\nexport const scaleVariants: Template[] = [\n  scale,\n  variant(scale, 'scale-02', 'Dive 02', { anchor: 'tl', direction: 'in', zoom: 45 }),\n  variant(scale, 'scale-03', 'Dive 03', { anchor: 'br', direction: 'out', zoom: 55 }),\n  variant(scale, 'scale-04', 'Dive 04', { anchor: 'center', direction: 'in', zoom: 20, spin: 'on', spinAmt: 10 }),\n];\n",
  "scatter.ts": "import type { Template } from './types';\nimport { frac, lerp, hash2 } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Parallax Scatter — a seeded field of tiles scattered across the canvas at\n// random depths, drifting vertically at depth-proportional speeds (nearer =\n// faster and larger). The seed makes the scatter fully reproducible; each\n// card's wrap count is quantized separately so the whole clip loops exactly.\nconst scatter: Template = {\n  meta: {\n    id: 'parallax-05', name: 'Drift Scatter', group: 'Drift',\n    defaultEasing: { id: 'linear' }, repeatAssets: true,\n  },\n\n  controls: [\n    { key: 'count',        label: 'Count',      type: 'slider', min: 6, max: 120, step: 1,   default: 24 },\n    { key: 'cardSize',     label: 'Plane Size', type: 'slider', min: 40, max: 300, step: 1,  default: 130 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1, default: 14 },\n    { key: 'spread',       label: 'Spread',     type: 'slider', min: 200, max: 1400, step: 10, default: 800 },\n    { key: 'seed',         label: 'Seed',       type: 'slider', min: 1, max: 999, step: 1,   default: 1 },\n    { key: 'speed',        label: 'Speed',      type: 'slider', min: 0.1, max: 2, step: 0.1, default: 0.5 },\n    { key: 'depthFade',    label: 'Depth Fade', type: 'toggle', options: ['on','off'],       default: 'on' },\n    { key: 'direction',    label: 'Direction',  type: 'toggle', options: ['up','down'],      default: 'up' },\n    { key: 'offset',       label: 'Offset',     type: 'xypad',                               default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    // reproducible per-card randoms — same seed, same field\n    const d = hash2(index, v.seed * 1.31);            // depth 0 (far) .. 1 (near)\n    const x0 = (hash2(index, v.seed) - 0.5) * v.spread;\n    const y0 = hash2(index, v.seed * 2.17);           // start position along the travel span\n\n    // travel window incl. offscreen margin so wraps happen out of sight\n    const span = ctx.height + v.cardSize * 1.6;\n\n    // per-card whole laps per clip (deeper = slower) → exact loop for every card\n    const laps = Math.max(1, Math.round(v.speed * ctx.duration * (0.3 + d)));\n    const t = ctx.easedPhase((frame / ctx.totalFrames) * laps);\n    // travel parameter wraps in [0,1); up = drift toward negative y\n    const u = frac(y0 + (v.direction === 'down' ? t : -t));\n    const y = (u - 0.5) * span;\n\n    const scale = (v.cardSize / BASE) * lerp(0.55, 1.3, d);\n    const alpha = v.depthFade === 'on' ? lerp(0.35, 1, d) : 1;\n\n    return {\n      x: x0 + v.offset.x,\n      y: y + v.offset.y,\n      scale,\n      rotation: 0,\n      alpha,\n      depth: d, // nearer tiles draw on top\n    };\n  },\n};\n\nexport const scatterVariants: Template[] = [\n  scatter,\n  variant(scatter, 'parallax-06', 'Drift Scatter 02', {\n    count: 60, spread: 1200, seed: 7, cardSize: 90, speed: 0.8,\n  }),\n];\n",
  "spin.ts": "import type { Template } from './types';\nimport { TAU, loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\nconst DEG = Math.PI / 180;\n\n// Spin — port of Originkit's \"Spin Image\". Cards ride an ellipse whose major\n// axis lies on the canvas TL→BR diagonal; the whole orbit plane is then tipped\n// in 3D by the curve controls (Curve X ≈ rotateY, Curve Y ≈ rotateX) and seen\n// through a perspective camera one canvas-edge away. Cards stay billboarded —\n// always facing the viewer — so the motion projects exactly onto the 2D\n// engine: only position, perspective size, and stacking change.\nconst spin: Template = {\n  meta: {\n    id: 'orbit-spin-01', name: 'Spin 01', group: 'Orbit',\n    defaultEasing: { id: 'linear' }, cardAspect: 1,\n  },\n\n  controls: [\n    { key: 'direction',    label: 'Direction',     type: 'toggle', options: ['forward','reverse'], default: 'forward' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 2, max: 16, step: 1,   default: 8 },\n    { key: 'width',        label: 'Orbit Width',   type: 'slider', min: 10, max: 150, step: 1, default: 70 },\n    { key: 'squash',       label: 'Flatten',       type: 'slider', min: 5, max: 100, step: 1,  default: 35 },\n    { key: 'xCurve',       label: 'Curve X',       type: 'slider', min: -90, max: 90, step: 1, default: 63 },\n    { key: 'yCurve',       label: 'Curve Y',       type: 'slider', min: -90, max: 90, step: 1, default: -47 },\n    { key: 'path',         label: 'Path',          type: 'toggle', options: ['curved','straight'], default: 'curved' },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 800, step: 1, default: 200 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 12 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 4, step: 0.1,  default: 1.2 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n    { key: 'fade',         label: 'Fade',          type: 'slider', min: 0, max: 100, step: 1,  default: 15 },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const dir = v.direction === 'reverse' ? -1 : 1;\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count) * dir);\n    const phi = ((index - phase) / count) * TAU;\n\n    // Ellipse in its own plane; major half-axis a as % of canvas width,\n    // minor axis squashed, the whole shape rotated onto the TL→BR diagonal.\n    const a = Math.max(1, ((v.width / 100) * ctx.width) / 2);\n    const b = a * (v.squash / 100);\n    const tilt = Math.atan2(ctx.height, ctx.width);\n    const ex = Math.cos(phi) * a;\n    const ey = Math.sin(phi) * b;\n    const x0 = ex * Math.cos(tilt) - ey * Math.sin(tilt);\n    const y0 = ex * Math.sin(tilt) + ey * Math.cos(tilt);\n\n    // Tip the orbit plane: rotateY(xCurve) ∘ rotateX(−yCurve), CSS axes\n    // (y down, +z toward the viewer). +90 X → left forward; +90 Y → top forward.\n    const ax = -v.yCurve * DEG;\n    const ay = v.xCurve * DEG;\n    const y1 = y0 * Math.cos(ax);\n    const z1 = y0 * Math.sin(ax);\n    const x2 = x0 * Math.cos(ay) + z1 * Math.sin(ay);\n    const z2 = -x0 * Math.sin(ay) + z1 * Math.cos(ay);\n\n    // Perspective camera one long-edge away (source: 1200px on a 1200 frame).\n    const d = Math.max(ctx.width, ctx.height);\n    const pf = d / Math.max(d - z2, d * 0.05);\n\n    // Curved path sizes by major-axis depth (0.6 back … 1.4 front); straight\n    // keeps cards uniform and lets only perspective breathe.\n    const dNorm = (Math.cos(phi) + 1) / 2;\n    const sf = v.path === 'curved' ? 0.6 + 0.8 * dNorm : 1;\n\n    return {\n      x: x2 * pf + v.offset.x,\n      y: y1 * pf + v.offset.y,\n      scale: (v.cardSize / BASE) * sf * pf,\n      rotation: 0,\n      alpha: 1 - (v.fade / 100) * (1 - dNorm),\n      // Nearer wins; flat (zero-curve) orbits tie-break lower-on-screen in\n      // front, matching the source's y-based stacking.\n      depth: (z2 / a + 1) / 2 + (y1 / a) * 0.1,\n    };\n  },\n};\n\nexport const spinVariants: Template[] = [\n  spin, // Spin 01 — the Originkit preview pose (63 / −47)\n  variant(spin, 'orbit-spin-02', 'Spin 02', {\n    xCurve: 0, yCurve: -70, squash: 60, count: 10, cardSize: 160, speed: 0.8,\n  }),\n  variant(spin, 'orbit-spin-03', 'Spin 03', {\n    xCurve: -80, yCurve: -15, count: 6, cardSize: 300, width: 90, fade: 35,\n  }),\n];\n",
  "spiral.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\nconst lerp = (a: number, b: number, t: number) => a + (b - a) * t;\n\n// Spiral — the camera corkscrews through a helix of cards (DNA / spiral\n// staircase): continuous rotation around the axis plus looping vertical travel.\nconst spiral: Template = {\n  meta: { id: 'spiral-01', name: 'Helix 01', group: 'Helix', defaultEasing: { id: 'linear' } },\n\n  controls: [\n    { key: 'direction',    label: 'Direction',     type: 'toggle', options: ['forward','reverse'], default: 'forward' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 8, max: 70, step: 1,   default: 40 },\n    { key: 'radius',       label: 'Radius',        type: 'slider', min: 80, max: 600, step: 1, default: 300 },\n    { key: 'turns',        label: 'Turns',         type: 'slider', min: 1, max: 6, step: 1,    default: 3 },\n    { key: 'pitch',        label: 'Pitch',         type: 'slider', min: 10, max: 120, step: 1, default: 40 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 20, max: 300, step: 1, default: 110 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 12 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 3, step: 0.1,  default: 0.5 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const dir = v.direction === 'reverse' ? -1 : 1;\n    // Both the helix angle and the vertical travel have period t=1, so lock\n    // the clip to a whole number of helix cycles.\n    const t = (frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration) * dir;\n    const sizeFactor = v.cardSize / BASE;\n\n    // Angle around the helix axis.\n    const a = index * (Math.PI * 2 * v.turns / count) + t * Math.PI * 2;\n    const x = Math.sin(a) * v.radius + v.offset.x;\n    const depthN = (Math.cos(a) + 1) / 2; // 1 = front, 0 = back\n\n    // Vertical travel that loops seamlessly through one full helix span.\n    const span = count * v.pitch;\n    const raw = index * v.pitch - t * span;\n    const y = (((raw % span) + span) % span) - span / 2 + v.offset.y;\n\n    const scale = sizeFactor * lerp(0.4, 1.15, depthN);\n    // Fade with depth, and taper at the top/bottom ends of the travel.\n    const alpha = lerp(0.2, 1, depthN) * Math.min(1, (1 - Math.abs(y) / (span / 2)) * 2 + 0.2);\n\n    return {\n      x,\n      y,\n      scale,\n      rotation: 0,\n      alpha,\n      depth: depthN,\n    };\n  },\n};\n\nexport const spiralVariants: Template[] = [\n  spiral, // Spiral 01 — classic staircase\n  variant(spiral, 'spiral-02', 'Helix 02', {\n    turns: 5, radius: 200, pitch: 30,\n  }),\n  variant(spiral, 'spiral-03', 'Helix 03', {\n    turns: 2, radius: 480, pitch: 70, count: 30,\n  }),\n  variant(spiral, 'spiral-04', 'Helix 04', {\n    turns: 6, radius: 140, pitch: 20, count: 60, cardSize: 80,\n  }),\n];\n",
  "stack.ts": "import type { Template } from './types';\nimport { frac, clamp, smooth, loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Stack — a perspective deck: the front card lifts away while the ones behind\n// advance forward one slot. Rebuilt from the reference model (learnings/STACK.md):\n// a stepped pointer advances one card per step, and each follower moves on its\n// OWN staggered, eased timeline (anticipation) — so the deck reads card-by-card\n// rather than as a rigid block. The exiting card stays opaque and fades only in\n// the last 10% of its travel (no fade-from-top, no hard cut).\nconst stack: Template = {\n  meta: { id: 'stack-01', name: 'Shuffle 01', group: 'Shuffle', defaultEasing: { id: 'smooth' } },\n\n  controls: [\n    { key: 'direction',    label: 'Direction',     type: 'toggle', options: ['down','up'], default: 'down' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 2, max: 20, step: 1,   default: 6 },  // pool that cycles\n    { key: 'visible',      label: 'Visible',       type: 'slider', min: 2, max: 8, step: 1,    default: 3 },  // cards shown in the stack\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 800, step: 1, default: 300 },\n    { key: 'zoom',         label: 'Zoom',          type: 'slider', min: 50, max: 300, step: 1, default: 100 }, // whole-deck scale %\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 12 },\n    { key: 'perspective',  label: 'Perspective',   type: 'slider', min: 0, max: 1000, step: 1, default: 0 }, // extra vertical gap between slots\n    { key: 'stagger',      label: 'Stagger',       type: 'slider', min: 0, max: 0.5, step: 0.01, default: 0.14 }, // per-card delay\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 4, step: 0.1,  default: 0.6 }, // steps/sec\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const n = Math.max(1, Math.round(count));\n    const dir = v.direction === 'up' ? -1 : 1;\n    const sizeFactor = (v.cardSize / BASE) * ((v.zoom ?? 100) / 100); // zoom scales the whole deck\n    const stepY = v.cardSize * 0.31 + v.perspective * 0.30;   // px gap between stacked slots\n    const vis = Math.min(Math.round(v.visible), n);\n\n    // Stepped pointer: advances one card per (1/speed) seconds. The cycle\n    // repeats every `n` steps — loop-lock to whole deck rotations per clip.\n    const pointer = (frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, n);\n    const base = Math.floor(pointer);\n    const s = frac(pointer);                                  // progress through the current step, 0..1\n\n    const exitFrac = 0.35;                                    // front card leaves in the first 35% of the step\n    const fadeStart = 0.9, fadeWin = 1 - fadeStart;           // fade only in the last 10% of travel\n    const stag = v.stagger;\n\n    const L = ((index - base) % n + n) % n;                   // integer slot at step start (0 = front)\n\n    // Continuous slot `cs` (L → L-1). The front card exits fast; followers each\n    // ease in on their own delayed timeline → individual, staggered motion.\n    let cs: number;\n    if (L === 0) {\n      cs = -clamp(s / exitFrac, 0, 1);                        // 0 → -1 quickly\n    } else {\n      const d = (L - 1) * stag;                               // cards nearer the front move first\n      const local = clamp((s - d) / Math.max(0.05, 1 - d), 0, 1);\n      cs = L - ctx.ease(local);                               // eased by the scene curve\n    }\n\n    let y: number, scale: number, alpha: number, depth: number;\n    if (cs < 0) {                                             // EXITING — descend opaque, fade only at the very end\n      const ex = -cs;                                         // 0..1\n      alpha = ex < fadeStart ? 1 : 1 - smooth((ex - fadeStart) / fadeWin);\n      y = dir * (ex * stepY);\n      scale = sizeFactor * (1 + ex * 0.02);\n      depth = 3000;                                           // in front while leaving\n    } else if (cs <= vis) {                                   // VISIBLE STACK — front larger, back smaller & higher\n      scale = sizeFactor * (1 - cs * 0.07);\n      y = dir * (-cs * stepY);\n      alpha = 1;\n      depth = 2000 - cs * 10;\n    } else if (cs <= vis + 1) {                               // ENTERING from the back (mirror of the exit fade)\n      const slot = Math.min(cs, vis);\n      const ep = (vis + 1) - cs;                              // 0 (appearing) .. 1 (in the stack)\n      scale = sizeFactor * (1 - slot * 0.07);\n      y = dir * (-slot * stepY);\n      alpha = ep < fadeWin ? smooth(ep / fadeWin) : 1;\n      depth = 2000 - slot * 10;\n    } else {                                                  // hidden\n      return { x: v.offset.x, y: v.offset.y, scale: 0, rotation: 0, alpha: 0, depth: -1 };\n    }\n\n    return {\n      x: v.offset.x,\n      y: y + v.offset.y,\n      scale,\n      rotation: 0,\n      alpha,\n      depth,\n    };\n  },\n};\n\nexport const stackVariants: Template[] = [\n  stack, // Stack 01 — deck advance with anticipation\n  variant(stack, 'stack-02', 'Shuffle 02', {\n    visible: 4, stagger: 0.24, perspective: 0, speed: 0.4,\n  }),\n];\n",
  "stories.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { cardPath } from './cardPath';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Stories — a horizontal strip with one dominant featured card and small\n// neighbours peeking at the edges. Flat (no fake-3D), fades to the sides.\nconst stories: Template = {\n  meta: { id: 'stories-01', name: 'Spotlight 01', group: 'Spotlight', defaultEasing: { id: 'linear' } },\n\n  controls: [\n    { key: 'direction',    label: 'Direction',     type: 'toggle', options: ['forward','reverse'], default: 'forward' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 1, max: 12, step: 1,   default: 5 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 800, step: 1, default: 300 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 16 },\n    { key: 'gap',          label: 'Gap',           type: 'slider', min: 0, max: 600, step: 1,  default: 110 },\n    { key: 'bigScale',     label: 'Big Scale',     type: 'slider', min: 100, max: 240, step: 1, default: 170 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 4, step: 0.1,  default: 0.4 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: 0 } },\n    { key: 'fade',         label: 'Fade',          type: 'slider', min: 0, max: 100, step: 1,  default: 40 },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const dir = v.direction === 'reverse' ? -1 : 1;\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count) * dir);\n    const sizeFactor = v.cardSize / BASE;\n\n    const p = cardPath({ kind: 'line', index, count, phase, gap: 1, wrap: true });\n    const spacing = (v.cardSize + v.gap) * sizeFactor;\n\n    const scale = sizeFactor * (1 + (v.bigScale / 100 - 1) * p.featuredness);\n    const alpha = 1 - (v.fade / 100) * (1 - p.depthNorm);\n\n    return {\n      x: p.x * spacing + v.offset.x,\n      y: v.offset.y,\n      scale,\n      rotation: 0,\n      alpha,\n      depth: p.depthNorm,\n    };\n  },\n};\n\nexport const storiesVariants: Template[] = [\n  stories, // Stories 01 — dominant centre\n  variant(stories, 'stories-02', 'Spotlight 02', {\n    gap: 30, bigScale: 210, fade: 65, cornerRadius: 24, speed: 0.3,\n  }),\n];\n",
  "storiesFocus.ts": "import type { Template } from './types';\nimport { smooth, lerp, loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Stories Focus — an Instagram-stories layout: one large focus frame plus a\n// tray of thumbnails. A selector steps through the tray; the active thumbnail\n// scales and drifts up into the big frame while the others dim.\n//\n// Single-transform trick: every slot has a fixed TRAY pose; its activation\n// f∈[0,1] (wrap-folded distance from the stepping selector) blends the pose\n// toward the shared BIG-FRAME pose. At the count→0 wrap the outgoing and\n// incoming cards cross-blend, so the loop is seamless.\nconst storiesFocus: Template = {\n  meta: { id: 'stories-03', name: 'Spotlight 03', group: 'Spotlight', defaultEasing: { id: 'snap' } },\n\n  controls: [\n    { key: 'count',        label: 'Count',          type: 'slider', min: 3, max: 10, step: 1,   default: 5 },\n    { key: 'bigScale',     label: 'Big Scale',      type: 'slider', min: 100, max: 200, step: 1, default: 115 }, // % of the base big-frame size\n    { key: 'bigDrift',     label: 'Big Drift',      type: 'slider', min: 0, max: 200, step: 1,  default: 40 },  // px the big frame drifts as the selector passes\n    { key: 'thumbSize',    label: 'Thumb Size',     type: 'slider', min: 40, max: 200, step: 1, default: 85 },\n    { key: 'gap',          label: 'Tray Gap',       type: 'slider', min: 0, max: 120, step: 1,  default: 18 },\n    { key: 'dimAmount',    label: 'Dim',            type: 'slider', min: 0, max: 100, step: 1,  default: 20 },  // inactive thumb dimming %\n    { key: 'trayDirection',label: 'Tray Direction', type: 'pills', options: ['right','left','down','up'], default: 'right' },\n    { key: 'cornerRadius', label: 'Corner Radius',  type: 'slider', min: 0, max: 100, step: 1,  default: 16 },\n    { key: 'speed',        label: 'Speed',          type: 'slider', min: 0.1, max: 2, step: 0.1, default: 0.4 }, // steps/sec\n    { key: 'offset',       label: 'Offset',         type: 'xypad',                              default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    // selector phase steps through the tray; period = count so textures return\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count));\n\n    // wrapped signed distance from the selector; f = activation 0..1\n    let off = (((index - phase) % count) + count) % count;\n    if (off > count / 2) off -= count;\n    const f = smooth(Math.max(0, 1 - Math.abs(off)));\n\n    const horiz = v.trayDirection === 'right' || v.trayDirection === 'left';\n    const sgn = (v.trayDirection === 'right' || v.trayDirection === 'down') ? 1 : -1;\n\n    // fixed tray along the bottom edge (horiz) or right edge (vertical)\n    const step = v.thumbSize + v.gap;\n    const trayMain = sgn * (index - (count - 1) / 2) * step;\n    const trayX = horiz ? trayMain : ctx.width * 0.32;\n    const trayY = horiz ? ctx.height * 0.32 : trayMain;\n\n    // big frame pose: upper-centre (horiz tray) / centre-left (vertical tray),\n    // drifting through as the selector hands over (off runs 1 → -1)\n    const bigSize = Math.min(ctx.width, ctx.height) * 0.55 * (v.bigScale / 100);\n    const bigX = (horiz ? 0 : -ctx.width * 0.08) - off * v.bigDrift * (horiz ? 1 : 0);\n    const bigY = (horiz ? -ctx.height * 0.10 : 0) - off * v.bigDrift * (horiz ? 0 : 1);\n\n    const x = lerp(trayX, bigX, f) + v.offset.x;\n    const y = lerp(trayY, bigY, f) + v.offset.y;\n    const scale = lerp(v.thumbSize / BASE, bigSize / BASE, f);\n    const alpha = lerp(1 - v.dimAmount / 100, 1, f); // inactive thumbs dim\n\n    return { x, y, scale, rotation: 0, alpha, depth: f }; // active card on top\n  },\n};\n\nexport const storiesFocusVariants: Template[] = [\n  storiesFocus,\n  variant(storiesFocus, 'stories-04', 'Spotlight 04', {\n    trayDirection: 'down', bigScale: 160, dimAmount: 45, thumbSize: 70, gap: 12,\n  }),\n];\n",
  "tour.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\n// Tour — a slow cinematic camera pan-and-zoom across a scattered collage,\n// drifting focus between images. Cards live at fixed positions in a large\n// field; the camera glides through, emphasising whatever it passes over.\nconst BASE = 340;\nconst lerp = (a: number, b: number, t: number) => a + (b - a) * t;\nconst h = (k: number) => { const s = Math.sin(k * 127.1 + 1.7) * 43758.5453; return s - Math.floor(s); };\n\nconst tour: Template = {\n  meta: { id: 'tour-01', name: 'Voyage 01', group: 'Voyage', defaultEasing: { id: 'smooth' } },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 4, max: 24, step: 1,    default: 14 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 50, max: 400, step: 1,  default: 200 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,   default: 14 },\n    { key: 'spread',       label: 'Spread',        type: 'slider', min: 400, max: 1600, step: 1, default: 1000 },\n    { key: 'zoom',         label: 'Zoom',          type: 'slider', min: 0, max: 60, step: 1,    default: 25 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 2, step: 0.1,   default: 0.5 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                               default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const sizeFactor = v.cardSize / BASE;\n\n    // fixed scatter in a large field, each card its own size\n    const px = (h(index) - 0.5) * v.spread;\n    const py = (h(index + 37.2) - 0.5) * v.spread;\n    const cardBaseSize = sizeFactor * (0.7 + h(index + 5) * 0.6);\n\n    // slow smooth camera drift + gentle zoom breathing. Each oscillator gets\n    // its own whole number of revolutions per clip (loop-locked); the original\n    // 0.7/0.9/0.6 rad/s frequencies become the per-axis rev/sec ratios.\n    const u = frame / ctx.totalFrames;\n    const TAU = Math.PI * 2;\n    const n1 = loopCycles((v.speed * 0.7) / TAU, ctx.duration);\n    const n2 = loopCycles((v.speed * 0.9) / TAU, ctx.duration);\n    const n3 = loopCycles((v.speed * 0.6) / TAU, ctx.duration);\n    const camX = Math.sin(TAU * u * n1) * v.spread * 0.4;\n    const camY = Math.cos(TAU * u * n2) * v.spread * 0.3;\n    const camZoom = 1 + v.zoom / 100 * (0.5 + 0.5 * Math.sin(TAU * u * n3));\n\n    // world → screen\n    const x = (px - camX) * camZoom + v.offset.x;\n    const y = (py - camY) * camZoom + v.offset.y;\n    let scale = cardBaseSize * camZoom;\n\n    // emphasise whatever the camera centres on\n    const dist = Math.hypot(px - camX, py - camY);\n    const focus = Math.max(0, 1 - dist / (v.spread * 0.35));\n    scale *= 1 + focus * 0.15;\n\n    return {\n      x,\n      y,\n      scale,\n      rotation: 0,\n      alpha: lerp(0.5, 1, focus),\n      depth: focus + h(index) * 0.01,\n    };\n  },\n};\n\nexport const tourVariants: Template[] = [\n  tour,\n  variant(tour, 'tour-02', 'Voyage 02', { spread: 700, zoom: 40, count: 18 }),\n  variant(tour, 'tour-03', 'Voyage 03', { spread: 1400, zoom: 15, count: 10 }),\n  variant(tour, 'tour-04', 'Voyage 04', { spread: 1000, zoom: 55, count: 24 }),\n];\n",
  "wheel.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { cardPath } from './cardPath';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Wheel — cards on a rotating ring (or a fan arc). Featured card is the one\n// nearest the top of the wheel; Spin Thumbs tilts cards along the tangent.\nconst wheel: Template = {\n  meta: { id: 'wheel-01', name: 'Ferris 01', group: 'Ferris', defaultEasing: { id: 'flow' } },\n\n  controls: [\n    { key: 'direction',    label: 'Direction',     type: 'toggle', options: ['forward','reverse'], default: 'forward' },\n    { key: 'mode',         label: 'Path',          type: 'toggle', options: ['ring','fan'], default: 'fan' },\n    { key: 'spinThumbs',   label: 'Spin Thumbs',   type: 'toggle', options: ['on','off'], default: 'on' },\n    { key: 'count',        label: 'Count',         type: 'slider', min: 3, max: 20, step: 1,   default: 5 },\n    { key: 'radius',       label: 'Ring Radius',   type: 'slider', min: 100, max: 900, step: 1, default: 620 },\n    { key: 'cardSize',     label: 'Thumb Size',    type: 'slider', min: 40, max: 600, step: 1, default: 190 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,  default: 10 },\n    { key: 'bigScale',     label: 'Big Scale',     type: 'slider', min: 100, max: 200, step: 1, default: 115 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0, max: 4, step: 0.1,  default: 0.5 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                              default: { x: 0, y: -160 } },\n    { key: 'fade',         label: 'Fade',          type: 'slider', min: 0, max: 100, step: 1,  default: 0 },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const dir = v.direction === 'reverse' ? -1 : 1;\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count) * dir);\n    const sizeFactor = v.cardSize / BASE;\n\n    const kind = v.mode === 'fan' ? 'arc' : 'ring';\n    // Fan wraps too: cards recycle through the arc window so the sweep loops\n    // seamlessly instead of drifting off the end of the arc.\n    const p = cardPath({\n      kind, index, count, phase,\n      radius: v.radius,\n      arcSpan: Math.PI * 0.9,\n      wrap: true,\n    });\n\n    // tangent angle at this position (ring: from centre; fan: arc param)\n    let angle = 0;\n    const off = ((index - phase) % count + count) % count;\n    if (kind === 'ring') {\n      angle = (off / count) * Math.PI * 2;\n    } else {\n      const span = Math.PI * 0.9;\n      const offS = off > count / 2 ? off - count : off;\n      angle = -span / 2 + (offS + count / 2) * (span / count);\n    }\n\n    const scale = sizeFactor * (1 + (v.bigScale / 100 - 1) * p.featuredness);\n    const alpha = 1 - (v.fade / 100) * (1 - p.depthNorm);\n\n    return {\n      x: p.x + v.offset.x,\n      y: p.y + v.offset.y,\n      scale,\n      rotation: v.spinThumbs === 'on' ? angle : 0,\n      alpha,\n      depth: p.depthNorm,\n    };\n  },\n};\n\nexport const wheelVariants: Template[] = [\n  wheel, // Wheel 01 — top fan, tilted thumbs\n  variant(wheel, 'wheel-02', 'Ferris 02', {\n    mode: 'ring', count: 8, radius: 340, cardSize: 230, speed: 0.4,\n    offset: { x: 0, y: 0 }, bigScale: 100,\n  }),\n  variant(wheel, 'wheel-03', 'Ferris 03', {\n    mode: 'ring', count: 12, radius: 380, cardSize: 130, speed: 0.7,\n    offset: { x: 0, y: 0 }, bigScale: 125,\n  }),\n  variant(wheel, 'wheel-04', 'Ferris 04', {\n    mode: 'ring', count: 20, radius: 400, cardSize: 60, speed: 1,\n    offset: { x: 0, y: 0 }, bigScale: 100, cornerRadius: 24,\n  }),\n];\n",
  "wipe.ts": "import type { Template } from './types';\nimport { loopCycles } from './motion';\nimport { variant } from './variant';\n\n// Wipe — full-frame images revealed by a directional push. The incoming\n// full-bleed image slides in from an edge, hard-covering the previous one;\n// the just-arrived image holds at centre until the next one pushes over it.\nconst BASE = 340;\n\nconst wipe: Template = {\n  meta: { id: 'wipe-01', name: 'Takeover 01', group: 'Takeover', defaultEasing: { id: 'linear' }, cardAspect: 'canvas' },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 2, max: 8, step: 1,     default: 4 },\n    { key: 'direction',    label: 'Direction',     type: 'pills',  options: ['left','right','up','down'], default: 'left' },\n    { key: 'zoom',         label: 'Zoom',          type: 'slider', min: 80, max: 160, step: 1,  default: 110 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,   default: 0 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0.2, max: 3, step: 0.1, default: 0.7 },\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                               default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    // full-bleed cover scale so the image fills the frame\n    const scale = (ctx.height / BASE) * 1.15 * (v.zoom / 100);\n\n    const phase = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count));\n    // lifecycle w ∈ [0, count): 0 = this image just fully arrived at centre\n    const w = (((phase - index) % count) + count) % count;\n\n    let ox = 0;\n    let oy = 0;\n    let depth = -w; // most-recent (small w) drawn on top\n\n    const arriving = count - w; // small positive → arriving soon\n    if (arriving < 1) {\n      const e = arriving; // 1 (off-screen) → 0 (centred)\n      const horizontal = v.direction === 'left' || v.direction === 'right';\n      const span = horizontal ? ctx.width : ctx.height;\n      const sgn = v.direction === 'left' || v.direction === 'up' ? 1 : -1;\n      if (horizontal) ox = sgn * e * span;\n      else oy = sgn * e * span;\n      depth = 10; // ride on top while sliding in\n    }\n\n    return {\n      x: ox + v.offset.x,\n      y: oy + v.offset.y,\n      scale,\n      rotation: 0,\n      alpha: 1,\n      depth,\n    };\n  },\n};\n\nexport const wipeVariants: Template[] = [\n  wipe, // Wipe 01 — push from the left\n  variant(wipe, 'wipe-02', 'Takeover 02', {\n    direction: 'up', zoom: 120, speed: 0.9,\n  }),\n  variant(wipe, 'wipe-03', 'Takeover 03', {\n    count: 6, direction: 'right', zoom: 100, speed: 0.5,\n  }),\n];\n",
  "zoom.ts": "import type { Template } from './types';\nimport { smooth, clamp, loopCycles } from './motion';\nimport { variant } from './variant';\n\nconst BASE = 340;\n\n// Scale Zoom — an infinite zoom through nested images. Each layer's scale is\n// an exponential of its wrapped stack position, so layers continuously grow\n// past the camera (bloom) or shrink inward (recede) and recycle, giving a\n// seamless endless zoom. Layers fade at their extreme scales.\nconst zoom: Template = {\n  meta: {\n    id: 'scale-05', name: 'Dive Zoom', group: 'Dive',\n    defaultEasing: { id: 'linear' }, repeatAssets: true, cardAspect: 'canvas',\n  },\n\n  controls: [\n    { key: 'count',        label: 'Count',         type: 'slider', min: 3, max: 10, step: 1,     default: 6 },\n    { key: 'zoomBase',     label: 'Zoom Ratio',    type: 'slider', min: 1.2, max: 3, step: 0.05, default: 1.6 }, // scale ratio between adjacent layers\n    { key: 'mode',         label: 'Mode',          type: 'toggle', options: ['bloom','recede'],  default: 'bloom' },\n    { key: 'growFrom',     label: 'Grow From',     type: 'pills', options: ['center','top','bottom','left','right'], default: 'center' },\n    { key: 'fade',         label: 'Edge Fade',     type: 'slider', min: 0, max: 100, step: 1,    default: 70 },\n    { key: 'cardSize',     label: 'Plane Size',    type: 'slider', min: 100, max: 800, step: 1,  default: 520 },\n    { key: 'cornerRadius', label: 'Corner Radius', type: 'slider', min: 0, max: 100, step: 1,    default: 12 },\n    { key: 'speed',        label: 'Speed',         type: 'slider', min: 0.1, max: 2, step: 0.1,  default: 0.35 }, // layers/sec\n    { key: 'offset',       label: 'Offset',        type: 'xypad',                                default: { x: 0, y: 0 } },\n  ],\n\n  transform: (frame, index, count, v, ctx) => {\n    const dir = v.mode === 'recede' ? -1 : 1;\n    // q advances in layer units; period = count so each layer returns to its\n    // exact nesting depth at the loop point.\n    const q = ctx.easedPhase((frame / ctx.totalFrames) * loopCycles(v.speed, ctx.duration, count)) * dir;\n\n    // wrapped exponent e ∈ [-count/2, count/2): this layer's depth in the stack\n    let e = (((index - q) % count) + count) % count - count / 2;\n\n    // exponential nesting; cap so a nearly-faded layer never becomes GPU-huge\n    const s = Math.min(64, Math.pow(v.zoomBase, -e));\n\n    // alpha: fade layers approaching either extreme of the stack\n    const edge = Math.abs(e) / (count / 2);\n    const alpha = 1 - (v.fade / 100) * smooth(clamp((edge - 0.6) / 0.4, 0, 1));\n\n    // growFrom origin: scaling about an anchor point O — layers emerge at O\n    // when tiny and expand past the canvas centre as they grow\n    const O =\n      v.growFrom === 'top'    ? [0, -ctx.height * 0.4] :\n      v.growFrom === 'bottom' ? [0, ctx.height * 0.4] :\n      v.growFrom === 'left'   ? [-ctx.width * 0.4, 0] :\n      v.growFrom === 'right'  ? [ctx.width * 0.4, 0] : [0, 0];\n    const x = O[0] * (1 - s) + v.offset.x;\n    const y = O[1] * (1 - s) + v.offset.y;\n\n    return {\n      x,\n      y,\n      scale: (v.cardSize / BASE) * s,\n      rotation: 0,\n      alpha,\n      depth: s, // bigger (nearer) layers draw on top\n    };\n  },\n};\n\nexport const zoomVariants: Template[] = [\n  zoom,\n  variant(zoom, 'scale-06', 'Dive Recede', {\n    mode: 'recede', growFrom: 'top', zoomBase: 1.8, fade: 85, speed: 0.3,\n  }),\n];\n"
};

